{
  "name": "Smart Water Tracker - Ghi Nước Thông Minh",
  "description": "Ứng dụng theo dõi lượng nước uống hàng ngày với sự hỗ trợ từ AI Gemini để đưa ra lời khuyên sức khỏe cá nhân hóa.",
  "requestFramePermissions": ["geolocation"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Không tìm thấy phần tử root để gắn ứng dụng");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WaterLog {
  id: string;
  amount: number; // ml
  timestamp: number;
}

export interface DailyGoal {
  target: number; // ml
  date: string; // YYYY-MM-DD
}

export interface HydrationAdvice {
  message: string;
  status: 'good' | 'warning' | 'critical';
}

import { GoogleGenAI, Type } from "@google/genai";

export const getHydrationAdvice = async (
  currentIntake: number,
  goal: number,
  history: number[]
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Dựa trên dữ liệu sau của người dùng:
    - Lượng nước đã uống hôm nay: ${currentIntake}ml
    - Mục tiêu: ${goal}ml
    - Lịch sử uống nước (các lần gần nhất): ${history.join(', ')}ml

    Hãy đưa ra một lời khuyên ngắn gọn (tối đa 2 câu) và đánh giá trạng thái (good, warning, critical).
    Trả về định dạng JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            message: { type: Type.STRING },
            status: { type: Type.STRING, enum: ['good', 'warning', 'critical'] }
          },
          required: ['message', 'status']
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Lỗi AI Gemini:", error);
    return {
      message: "Uống đủ nước giúp cơ thể luôn tràn đầy năng lượng!",
      status: "good"
    };
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Droplets, 
  History, 
  Settings, 
  Trophy, 
  Trash2, 
  BrainCircuit,
  GlassWater
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { WaterLog, HydrationAdvice } from './types';
import { getHydrationAdvice } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [logs, setLogs] = useState<WaterLog[]>([]);
  const [goal, setGoal] = useState<number>(2000);
  const [advice, setAdvice] = useState<HydrationAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  // --- Tính toán ---
  const today = new Date().toISOString().split('T')[0];
  const todayLogs = logs.filter(log => new Date(log.timestamp).toISOString().split('T')[0] === today);
  const currentTotal = todayLogs.reduce((sum, log) => sum + log.amount, 0);
  const progress = Math.min((currentTotal / goal) * 100, 100);

  // --- Handlers ---
  const addWater = (amount: number) => {
    const newLog: WaterLog = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      timestamp: Date.now(),
    };
    setLogs(prev => [newLog, ...prev]);
  };

  const deleteLog = (id: string) => {
    setLogs(prev => prev.filter(log => log.id !== id));
  };

  const fetchAIAdvice = useCallback(async () => {
    if (currentTotal === 0) return;
    setLoadingAdvice(true);
    const result = await getHydrationAdvice(
      currentTotal, 
      goal, 
      todayLogs.slice(0, 5).map(l => l.amount)
    );
    setAdvice(result);
    setLoadingAdvice(false);
  }, [currentTotal, goal, todayLogs]);

  // --- Dữ liệu biểu đồ ---
  const chartData = [
    { name: 'Sáng', amount: todayLogs.filter(l => new Date(l.timestamp).getHours() < 12).reduce((s, l) => s + l.amount, 0) },
    { name: 'Chiều', amount: todayLogs.filter(l => new Date(l.timestamp).getHours() >= 12 && new Date(l.timestamp).getHours() < 18).reduce((s, l) => s + l.amount, 0) },
    { name: 'Tối', amount: todayLogs.filter(l => new Date(l.timestamp).getHours() >= 18).reduce((s, l) => s + l.amount, 0) },
  ];

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      {/* Header */}
      <header className="bg-white border-b px-4 py-6 sticky top-0 z-10 shadow-sm">
        <div className="max-w-md mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-200">
              <Droplets className="text-white" size={24} />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-cyan-500">
              Ghi Nước
            </h1>
          </div>
          <button 
            onClick={() => setShowSettings(!showSettings)}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            <Settings size={24} className="text-slate-500" />
          </button>
        </div>
      </header>

      <main className="max-w-md mx-auto p-4 space-y-6">
        {/* Settings Modal (Inline simple) */}
        {showSettings && (
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-blue-100 animate-in fade-in slide-in-from-top-4 duration-300">
            <label className="block text-sm font-medium text-slate-700 mb-2">Mục tiêu hàng ngày (ml)</label>
            <div className="flex gap-2">
              <input 
                type="number" 
                value={goal} 
                onChange={(e) => setGoal(Number(e.target.value))}
                className="flex-1 border rounded-xl px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
              />
              <button 
                onClick={() => setShowSettings(false)}
                className="bg-blue-600 text-white px-4 py-2 rounded-xl font-medium"
              >
                Lưu
              </button>
            </div>
          </div>
        )}

        {/* Progress Card */}
        <div className="bg-white rounded-3xl p-8 shadow-xl shadow-blue-100/50 border border-blue-50/50 relative overflow-hidden">
          <div className="relative z-10 flex flex-col items-center">
            <div 
              className="w-48 h-48 rounded-full border-8 border-slate-100 flex flex-col items-center justify-center water-wave shadow-inner"
              style={{ '--wave-top': `${100 - progress}%` } as any}
            >
              <span className="text-4xl font-black text-slate-800 z-10">{currentTotal}</span>
              <span className="text-sm font-medium text-slate-500 z-10">/ {goal}ml</span>
            </div>

            <div className="mt-8 grid grid-cols-2 gap-8 w-full">
              <div className="text-center">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Tiến độ</p>
                <p className="text-2xl font-bold text-blue-600">{Math.round(progress)}%</p>
              </div>
              <div className="text-center border-l">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Cần thêm</p>
                <p className="text-2xl font-bold text-slate-800">{Math.max(goal - currentTotal, 0)}ml</p>
              </div>
            </div>
          </div>
        </div>

        {/* AI Insight Card */}
        <div className="bg-gradient-to-br from-indigo-600 to-blue-500 rounded-3xl p-6 text-white shadow-lg shadow-indigo-200">
          <div className="flex items-center gap-2 mb-4">
            <BrainCircuit size={20} />
            <h2 className="font-bold">Trợ lý AI Gemini</h2>
            <button 
              onClick={fetchAIAdvice}
              disabled={loadingAdvice || currentTotal === 0}
              className="ml-auto text-xs bg-white/20 hover:bg-white/30 px-3 py-1 rounded-full transition-colors disabled:opacity-50"
            >
              {loadingAdvice ? "Đang nghĩ..." : "Cập nhật"}
            </button>
          </div>
          <p className="text-sm leading-relaxed opacity-90">
            {advice ? advice.message : "Uống một ly nước ngay bây giờ để nhận lời khuyên từ AI!"}
          </p>
          {advice?.status === 'warning' && (
            <div className="mt-3 bg-yellow-400/20 text-yellow-200 text-[10px] font-bold uppercase py-1 px-2 rounded-md inline-block">
              Nhắc nhở quan trọng
            </div>
          )}
        </div>

        {/* Quick Add Buttons */}
        <div className="grid grid-cols-4 gap-3">
          {[100, 200, 350, 500].map(amount => (
            <button
              key={amount}
              onClick={() => addWater(amount)}
              className="bg-white border-2 border-slate-100 hover:border-blue-200 p-4 rounded-2xl flex flex-col items-center gap-2 transition-all active:scale-95 shadow-sm"
            >
              <GlassWater className="text-blue-500" size={24} />
              <span className="text-xs font-bold text-slate-600">{amount}ml</span>
            </button>
          ))}
        </div>

        {/* Chart */}
        <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
          <h3 className="text-sm font-bold text-slate-800 mb-4 flex items-center gap-2">
            <History size={18} className="text-blue-500" />
            Thống kê hôm nay
          </h3>
          <div className="h-48 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#64748b'}} />
                <YAxis hide />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="amount" radius={[8, 8, 8, 8]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.amount > 0 ? '#3b82f6' : '#e2e8f0'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Recent History */}
        <div className="space-y-3">
          <h3 className="text-sm font-bold text-slate-800 px-1">Lịch sử gần đây</h3>
          {todayLogs.length === 0 ? (
            <div className="bg-slate-100/50 border-2 border-dashed border-slate-200 rounded-3xl p-8 text-center">
              <p className="text-sm text-slate-400 font-medium">Chưa có dữ liệu nào</p>
            </div>
          ) : (
            todayLogs.map(log => (
              <div 
                key={log.id} 
                className="bg-white p-4 rounded-2xl flex items-center justify-between shadow-sm border border-slate-50 group animate-in slide-in-from-left duration-300"
              >
                <div className="flex items-center gap-3">
                  <div className="bg-blue-50 p-2 rounded-xl">
                    <Droplets className="text-blue-500" size={18} />
                  </div>
                  <div>
                    <p className="text-sm font-bold text-slate-800">{log.amount}ml</p>
                    <p className="text-[10px] text-slate-400 font-medium">
                      {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </p>
                  </div>
                </div>
                <button 
                  onClick={() => deleteLog(log.id)}
                  className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-all opacity-0 group-hover:opacity-100"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            ))
          )}
        </div>
      </main>

      {/* Floating Action Button */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-white via-white to-transparent pointer-events-none">
        <div className="max-w-md mx-auto flex justify-center pointer-events-auto">
          <button 
            onClick={() => addWater(250)}
            className="bg-blue-600 text-white w-full py-4 rounded-2xl font-bold shadow-xl shadow-blue-200 flex items-center justify-center gap-2 hover:bg-blue-700 active:scale-[0.98] transition-all"
          >
            <Plus size={24} strokeWidth={3} />
            Thêm một ly (250ml)
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;

