export const formatCurrency = (val: number): string => {
  return new Intl.NumberFormat('vi-VN').format(val);
};

export const normalizePhoneForZalo = (phone: string): string => {
  let p = phone.replace(/\D/g, '');
  if (p.startsWith('0')) {
    p = '84' + p.substring(1);
  }
  return p;
};

export const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

import * as XLSX from 'xlsx';
import { Customer } from '../types';
import { formatCurrency } from './formatUtils';

export const exportToExcel = (data: Customer[], fileName: string) => {
  const exportData = data.map(c => ({
    'STT': c.stt,
    'Họ Tên': c.name,
    'Địa Chỉ': c.address,
    'SĐT': c.phone,
    'Số Cũ': c.oldIndex,
    'Số Mới': c.newIndex,
    'Tiêu Thụ': c.volume,
    'Tiền Nước': c.amount,
    'Nợ Cũ': c.oldDebt,
    'Tổng Cộng': c.balance,
    'Trạng Thái': c.status === 'paid' ? 'Đã thu' : 'Chưa thu',
    'Zalo': c.isZalo ? 'Có' : 'Không'
  }));

  const worksheet = XLSX.utils.json_to_sheet(exportData);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "KhachHang");
  XLSX.writeFile(workbook, `${fileName}.xlsx`);
};

export const parseExcelFile = async (file: File, listType: 'list1' | 'list2'): Promise<Partial<Customer>[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const json = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName]);

        const mapped = json.map((row: any) => ({
          stt: parseInt(row['STT'] || row['stt'] || 0),
          name: String(row['Họ Tên'] || row['name'] || row['ten'] || ''),
          address: String(row['Địa Chỉ'] || row['address'] || ''),
          phone: String(row['SĐT'] || row['phone'] || ''),
          oldIndex: parseFloat(row['Số Cũ'] || row['oldIndex'] || 0),
          oldDebt: parseFloat(row['Nợ Cũ'] || row['oldDebt'] || 0),
          isZalo: !!(row['Zalo'] || row['isZalo']),
          listType
        }));
        resolve(mapped);
      } catch (err) {
        reject(err);
      }
    };
    reader.readAsBinaryString(file);
  });
};

import { Customer } from '../types';
import { parseSafe } from '../utils/formatUtils';

export const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

export const syncWithGoogleSheets = async (url: string, activeTab: string): Promise<any[]> => {
  const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
  return await res.json();
};

