import * as XLSX from 'xlsx';
import { Customer } from '../types';

// Hàm tìm giá trị dựa trên nhiều tiêu đề cột có thể xảy ra
const getVal = (row: any, keys: string[]) => {
  for (const key of keys) {
    const foundKey = Object.keys(row).find(k => k.trim().toLowerCase() === key.toLowerCase());
    if (foundKey) return row[foundKey];
  }
  return undefined;
};

export const exportToExcel = (data: Customer[], fileName: string) => {
  const exportData = data.map(c => ({
    'STT': c.stt,
    'Họ Tên': c.name,
    'Địa Chỉ': c.address,
    'SĐT': c.phone,
    'Số Cũ': c.oldIndex,
    'Số Mới': c.newIndex,
    'Tiêu Thụ': c.volume,
    'Tiền Nước': c.amount,
    'Nợ Cũ': c.oldDebt,
    'Khách Đưa': c.paid,
    'Tổng Cộng': c.balance,
    'Zalo': c.isZalo ? 'X' : ''
  }));

  const worksheet = XLSX.utils.json_to_sheet(exportData);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "KhachHang");
  XLSX.writeFile(workbook, `${fileName}.xlsx`);
};

export const parseExcelFile = async (file: File, listType: 'list1' | 'list2'): Promise<Partial<Customer>[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const json = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName]);

        const mapped = json.map((row: any) => ({
          stt: parseInt(getVal(row, ['STT', 'Số TT', 'No']) || 0),
          name: String(getVal(row, ['Họ Tên', 'Tên', 'Khách Hàng', 'Name']) || ''),
          address: String(getVal(row, ['Địa Chỉ', 'Dia Chi', 'Address']) || ''),
          phone: String(getVal(row, ['SĐT', 'Số ĐT', 'Điện thoại', 'Phone']) || ''),
          oldIndex: parseFloat(getVal(row, ['Số Cũ', 'Chỉ số cũ', 'Old Index']) || 0),
          newIndex: parseFloat(getVal(row, ['Số Mới', 'Chỉ số mới', 'New Index']) || 0),
          oldDebt: parseFloat(getVal(row, ['Nợ Cũ', 'Tiền nợ', 'Old Debt']) || 0),
          paid: parseFloat(getVal(row, ['Khách Đưa', 'Đã thu', 'Paid']) || 0),
          isZalo: !!getVal(row, ['Zalo', 'Is Zalo', 'Vào Zalo']),
          listType
        }));
        resolve(mapped);
      } catch (err) {
        reject(err);
      }
    };
    reader.readAsBinaryString(file);
  });
};

