import * as XLSX from 'xlsx';
import { Customer } from '../types';

/**
 * Hàm hỗ trợ tìm giá trị trong hàng Excel dựa trên danh sách các tên cột có thể có
 */
const findVal = (row: any, keys: string[]) => {
  const rowKeys = Object.keys(row);
  for (const key of keys) {
    const match = rowKeys.find(k => k.trim().toLowerCase() === key.toLowerCase());
    if (match) return row[match];
  }
  return undefined;
};

export const exportToExcel = (data: Customer[], fileName: string) => {
  // Tạo dữ liệu xuất khẩu với đúng 12 cột theo mẫu ảnh của khách hàng
  const exportData = data.map(c => ({
    'STT': c.stt,
    'KHÁCH HÀNG': c.name.toUpperCase(),
    'ĐỊA CHỈ': c.address,
    'ĐIỆN THOẠI': c.phone,
    'CHỈ SỐ MỚI': c.newIndex || '',
    'CHỈ SỐ CŨ': c.oldIndex,
    'TIÊU THỤ': c.volume || '',
    'THÀNH TIỀN': c.amount || '',
    'NỢ KỲ TRƯỚC': c.oldDebt,
    'THANH TOÁN': (c.amount + c.oldDebt) || '',
    'NỢ LẠI': c.balance || '',
    'ĐÃ VÀO ZALO': c.isZalo ? 'x' : ''
  }));

  const worksheet = XLSX.utils.json_to_sheet(exportData);

  // Chỉnh độ rộng cột cơ bản để in đẹp
  const wscols = [
    {wch: 5},  // STT
    {wch: 25}, // KHÁCH HÀNG
    {wch: 15}, // ĐỊA CHỈ
    {wch: 12}, // ĐIỆN THOẠI
    {wch: 10}, // CHỈ SỐ MỚI
    {wch: 10}, // CHỈ SỐ CŨ
    {wch: 10}, // TIÊU THỤ
    {wch: 12}, // THÀNH TIỀN
    {wch: 12}, // NỢ KỲ TRƯỚC
    {wch: 12}, // THANH TOÁN
    {wch: 10}, // NỢ LẠI
    {wch: 8},  // ZALO
  ];
  worksheet['!cols'] = wscols;

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "GhiNuoc");
  XLSX.writeFile(workbook, `${fileName}.xlsx`);
};

export const parseExcelFile = async (file: File, listType: 'list1' | 'list2'): Promise<Partial<Customer>[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];

        // Đọc toàn bộ sheet dưới dạng mảng để tìm dòng tiêu đề
        const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
        let headerRowIndex = -1;

        // Tìm dòng chứa "STT" và "KHÁCH HÀNG" (thường là dòng 4 trong file của bạn)
        for (let i = 0; i < Math.min(rows.length, 20); i++) {
          const rowStr = JSON.stringify(rows[i]).toUpperCase();
          if (rowStr.includes("STT") && (rowStr.includes("KHÁCH HÀNG") || rowStr.includes("KHACH HANG"))) {
            headerRowIndex = i;
            break;
          }
        }

        if (headerRowIndex === -1) {
          throw new Error("Không tìm thấy dòng tiêu đề (STT, KHÁCH HÀNG) trong file Excel!");
        }

        // Đọc lại dữ liệu bắt đầu từ dòng tiêu đề đã tìm thấy
        const json: any[] = XLSX.utils.sheet_to_json(worksheet, { range: headerRowIndex });

        const mapped = json.filter(row => findVal(row, ['KHÁCH HÀNG', 'KHACH HANG', 'Tên'])).map((row: any) => ({
          stt: parseInt(findVal(row, ['STT', 'Số TT']) || 0),
          name: String(findVal(row, ['KHÁCH HÀNG', 'KHACH HANG', 'Tên Khách Hàng']) || '').trim(),
          address: String(findVal(row, ['ĐỊA CHỈ', 'DIA CHI', 'Địa chỉ']) || '').trim(),
          phone: String(findVal(row, ['ĐIỆN THOẠI', 'DIEN THOAI', 'SĐT', 'SDT']) || '').trim(),
          oldIndex: parseFloat(findVal(row, ['CHỈ SỐ CŨ', 'CHI SO CU', 'Số Cũ']) || 0),
          newIndex: parseFloat(findVal(row, ['CHỈ SỐ MỚI', 'CHI SO MOI', 'Số Mới']) || 0),
          oldDebt: parseFloat(findVal(row, ['NỢ KỲ TRƯỚC', 'NO KY TRUOC', 'Nợ cũ']) || 0),
          isZalo: String(findVal(row, ['ĐÃ VÀO ZALO', 'ZALO']) || '').toLowerCase().includes('x'),
          listType
        }));

        resolve(mapped);
      } catch (err) {
        reject(err);
      }
    };
    reader.readAsBinaryString(file);
  });
};

