import * as XLSX from 'xlsx';
import { Customer } from '../types';

/**
 * Hàm tìm giá trị trong hàng Excel dựa trên danh sách các tên cột có thể có
 */
const findVal = (row: any, keys: string[]) => {
  const rowKeys = Object.keys(row);
  for (const key of keys) {
    const match = rowKeys.find(k => k.trim().toLowerCase() === key.toLowerCase());
    if (match) return row[match];
  }
  return undefined;
};

export const exportToExcel = (data: Customer[], fileName: string) => {
  // Thứ tự 12 cột chuẩn xác theo ảnh mẫu của khách hàng
  const exportData = data.map(c => ({
    'STT': c.stt,
    'KHÁCH HÀNG': c.name.toUpperCase(),
    'ĐỊA CHỈ': c.address,
    'ĐIỆN THOẠI': c.phone,
    'CHỈ SỐ MỚI': c.newIndex || '',
    'CHỈ SỐ CŨ': c.oldIndex,
    'TIÊU THỤ': c.volume || '',
    'THÀNH TIỀN': c.amount || '',
    'NỢ KỲ TRƯỚC': c.oldDebt,
    'THANH TOÁN': c.paid || '', // Tiền khách đã đưa
    'NỢ LẠI': c.balance || '',  // Số tiền còn nợ lại
    'ĐÃ VÀO ZALO': c.isZalo ? 'x' : ''
  }));

  // Xuất file với header cố định để đảm bảo thứ tự cột A -> L
  const worksheet = XLSX.utils.json_to_sheet(exportData, {
    header: [
      'STT', 'KHÁCH HÀNG', 'ĐỊA CHỈ', 'ĐIỆN THOẠI', 
      'CHỈ SỐ MỚI', 'CHỈ SỐ CŨ', 'TIÊU THỤ', 'THÀNH TIỀN', 
      'NỢ KỲ TRƯỚC', 'THANH TOÁN', 'NỢ LẠI', 'ĐÃ VÀO ZALO'
    ]
  });

  // Định dạng độ rộng cột để in ấn đẹp (wch là số ký tự)
  const wscols = [
    {wch: 5},  // A: STT
    {wch: 25}, // B: KHÁCH HÀNG
    {wch: 12}, // C: ĐỊA CHỈ
    {wch: 12}, // D: ĐIỆN THOẠI
    {wch: 10}, // E: CHỈ SỐ MỚI
    {wch: 10}, // F: CHỈ SỐ CŨ
    {wch: 8},  // G: TIÊU THỤ
    {wch: 12}, // H: THÀNH TIỀN
    {wch: 12}, // I: NỢ KỲ TRƯỚC
    {wch: 12}, // J: THANH TOÁN
    {wch: 12}, // K: NỢ LẠI
    {wch: 10}, // L: ĐÃ VÀO ZALO
  ];
  worksheet['!cols'] = wscols;

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "GhiNuoc");
  XLSX.writeFile(workbook, `${fileName}.xlsx`);
};

export const parseExcelFile = async (file: File, listType: 'list1' | 'list2'): Promise<Partial<Customer>[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];

        const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1 });
        let headerRowIndex = -1;

        // Tìm dòng tiêu đề (Dòng 4 trong ảnh của bạn)
        for (let i = 0; i < Math.min(rows.length, 20); i++) {
          const rowStr = JSON.stringify(rows[i]).toUpperCase();
          if (rowStr.includes("STT") && (rowStr.includes("KHÁCH HÀNG") || rowStr.includes("KHACH HANG"))) {
            headerRowIndex = i;
            break;
          }
        }

        if (headerRowIndex === -1) {
          throw new Error("Không tìm thấy dòng tiêu đề (STT, KHÁCH HÀNG)!");
        }

        const json: any[] = XLSX.utils.sheet_to_json(worksheet, { range: headerRowIndex });

        const mapped = json.filter(row => findVal(row, ['KHÁCH HÀNG', 'KHACH HANG'])).map((row: any) => ({
          stt: parseInt(findVal(row, ['STT']) || 0),
          name: String(findVal(row, ['KHÁCH HÀNG', 'KHACH HANG']) || '').trim(),
          address: String(findVal(row, ['ĐỊA CHỈ', 'DIA CHI']) || '').trim(),
          phone: String(findVal(row, ['ĐIỆN THOẠI', 'DIEN THOAI']) || '').trim(),
          // Lưu ý: Đọc đúng cột E là Mới, F là Cũ theo ảnh
          newIndex: parseFloat(findVal(row, ['CHỈ SỐ MỚI', 'CHI SO MOI']) || 0),
          oldIndex: parseFloat(findVal(row, ['CHỈ SỐ CŨ', 'CHI SO CU']) || 0),
          oldDebt: parseFloat(findVal(row, ['NỢ KỲ TRƯỚC', 'NO KY TRUOC']) || 0),
          paid: parseFloat(findVal(row, ['THANH TOÁN', 'THANH TOAN']) || 0),
          isZalo: String(findVal(row, ['ĐÃ VÀO ZALO', 'ZALO']) || '').toLowerCase().includes('x'),
          listType
        }));

        resolve(mapped);
      } catch (err) {
        reject(err);
      }
    };
    reader.readAsBinaryString(file);
  });
};

import { Customer } from '../types';
import { parseSafe } from '../utils/formatUtils';

export const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);

  // Tiêu thụ = Số mới - Số cũ
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  // Tiền nước kỳ này
  const amt = vol * rate;
  // Tổng cộng cần trả = Tiền nước + Nợ cũ
  const totalDue = amt + od;
  // Nợ lại (Số dư) = Tổng cộng - Số tiền khách đã thanh toán
  const bal = totalDue - paid;

  return {
    ...cust,
    newIndex: ni, 
    oldIndex: oi, 
    oldDebt: od, 
    paid: paid,
    volume: vol, 
    amount: amt, 
    balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

