               <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Số tài khoản:</label><input className="w-full bg-white p-4 border rounded-xl font-black outline-none border-slate-200" type="text" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Tên chủ TK:</label><input className="w-full bg-white p-4 border rounded-xl font-black uppercase outline-none border-slate-200" type="text" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value})} /></div>
               <div className="h-px bg-slate-100 my-4"></div>
               <div className="space-y-1"><label className="text-[11px] font-black uppercase text-blue-600 ml-1 italic">Link Script 1 (Bộ 01):</label><input className="w-full bg-white p-4 border rounded-xl text-[10px] outline-none border-slate-200" type="text" value={config.sheetUrl1} onChange={e => setConfig({...config, sheetUrl1: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[11px] font-black uppercase text-indigo-600 ml-1 italic">Link Script 2 (Bộ 02):</label><input className="w-full bg-white p-4 border rounded-xl text-[10px] outline-none border-slate-200" type="text" value={config.sheetUrl2} onChange={e => setConfig({...config, sheetUrl2: e.target.value})} /></div>
            </div>

            <button onClick={() => setView('list')} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95 transition-all">Hoàn tất cấu hình</button>

            <div className="pt-8 text-center">
              <button 
                onClick={() => { if(confirm("CẢNH BÁO: Xóa sạch toàn bộ dữ liệu?")) { localStorage.clear(); location.reload(); } }} 
                className="text-rose-500 font-black text-[10px] uppercase tracking-widest active:opacity-50 flex items-center justify-center gap-1 mx-auto"
              >
                <Trash2 size={12}/> Xóa dữ liệu máy
              </button>
            </div>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white flex flex-col p-6 animate-in slide-in-from-bottom duration-200">
          <header className="flex items-center gap-4 mb-8 shrink-0"><button onClick={() => setView('list')} className="p-2 bg-slate-50 rounded-full"><ChevronLeft size={28}/></button><h1 className="text-xl font-black uppercase italic tracking-tight text-slate-800">Thống kê báo cáo</h1></header>
          <div className="grid grid-cols-2 gap-4 mb-6 shrink-0">
            <div className="bg-blue-50 p-6 rounded-3xl text-center shadow-sm"><p className="text-[10px] font-black uppercase text-blue-400 mb-1">Tổng khách</p><p className="text-3xl font-black text-blue-600 tracking-tighter">{stats.totalCust}</p></div>
            <div className="bg-emerald-50 p-6 rounded-3xl text-center shadow-sm"><p className="text-[10px] font-black uppercase text-emerald-400 mb-1">Đã ghi số</p><p className="text-3xl font-black text-emerald-600 tracking-tighter">{stats.recorded}</p></div>
          </div>
          <div className="bg-white border-2 rounded-[2.5rem] p-6 space-y-4 shadow-sm border-slate-100">
             <div className="flex justify-between font-bold text-slate-500 italic"><span>Tổng tiêu thụ:</span><span className="text-slate-900">{stats.totalVol} m³</span></div>
             <div className="flex justify-between font-bold text-blue-600 uppercase text-sm italic"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount)}</span></div>
             <div className="flex justify-between font-bold text-rose-600 uppercase text-sm italic"><span>Nợ kỳ trước:</span><span>{formatCurrency(stats.totalOldDebt)}</span></div>
          </div>
          <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `BaoCao_${activeTab}`)} className="w-full bg-blue-600 text-white py-4.5 rounded-2xl font-black uppercase shadow-xl mt-8 flex justify-center items-center gap-2 active:scale-95"><Download size={20}/> Xuất Excel báo cáo</button>
        </div>
      )}

      {(view === 'add_customer' || view === 'edit_customer') && (
        <div className="h-full bg-white flex flex-col overflow-y-auto animate-in slide-in-from-top duration-200">
          <header className="p-4 flex justify-between items-center border-b shrink-0"><button onClick={() => setView(view === 'add_customer' ? 'list' : 'detail')} className="p-2 text-slate-400 active:scale-90"><ChevronLeft size={32}/></button><h1 className="text-lg font-black text-slate-800 uppercase italic tracking-tight">{view === 'add_customer' ? 'Chèn khách mới' : 'Sửa khách hàng'}</h1><div className="w-10"></div></header>
          <div className="p-6 space-y-6 pb-20">
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Vị trí STT (Muốn chèn):</label><input className="w-full bg-slate-50 p-4 rounded-xl font-black border-2 border-slate-100 outline-none focus:border-blue-500" type="number" value={view === 'add_customer' ? addForm.stt : editForm.stt} onChange={e => view === 'add_customer' ? setAddForm({...addForm, stt: parseInt(e.target.value)}) : setEditForm({...editForm, stt: parseInt(e.target.value)})} /></div>
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Tên khách hàng:</label><input className="w-full bg-slate-50 p-4 rounded-xl font-bold border-2 border-slate-100 outline-none focus:border-blue-500 uppercase" type="text" placeholder="Nhập tên..." value={view === 'add_customer' ? addForm.name : editForm.name} onChange={e => view === 'add_customer' ? setAddForm({...addForm, name: e.target.value}) : setEditForm({...editForm, name: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Địa chỉ:</label><input className="w-full bg-slate-50 p-4 rounded-xl font-bold border-2 border-slate-100 outline-none focus:border-blue-500" type="text" placeholder="Số nhà, địa chỉ..." value={view === 'add_customer' ? addForm.address : editForm.address} onChange={e => view === 'add_customer' ? setAddForm({...addForm, address: e.target.value}) : setEditForm({...editForm, address: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Số điện thoại:</label><input className="w-full bg-slate-50 p-4 rounded-xl font-bold border-2 border-slate-100 outline-none focus:border-blue-500" type="tel" placeholder="09xxxx..." value={view === 'add_customer' ? addForm.phone : editForm.phone} onChange={e => view === 'add_customer' ? setAddForm({...addForm, phone: e.target.value}) : setEditForm({...editForm, phone: e.target.value})} /></div>
            {view === 'edit_customer' && (
              <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Nợ kỳ trước:</label><input className="w-full bg-slate-50 p-4 rounded-xl font-bold border-2 border-slate-100 outline-none focus:border-blue-500" type="number" value={editForm.oldDebt} onChange={e => setEditForm({...editForm, oldDebt: parseSafe(e.target.value)})} /></div>
            )}
            <button onClick={view === 'add_customer' ? handleAddCustomer : handleUpdateCustomer} className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95 transition-all">Lưu & Quay về</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

{
  "name": "Quản Lý Ghi Nước Chuyên Nghiệp",
  "description": "Hệ thống quản lý chỉ số nước, tính hóa đơn, tích hợp Zalo và thanh toán QR code.",
  "requestFramePermissions": [
    "geolocation",
    "microphone"
  ]
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  CloudDownload, Settings, ChevronLeft, Search, Loader2, 
  X, Banknote, Save, Trash2, Pencil, Plus, Download, BarChart3, QrCode, Phone, Copy, Mic, FileJson, UploadCloud,
  MessageCircle, FileSpreadsheet, ExternalLink, ChevronRight, MicOff
} from 'lucide-react';
import { exportToExcel, parseExcelFile, normalizePhoneForZalo, formatCurrency } from './utils';
import { Customer } from './types';

const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('water_data_final_v16');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState(() => {
    const saved = localStorage.getItem('water_config_v16');
    return saved ? JSON.parse(saved) : { 
      waterRate: 16.5, sheetUrl1: '', sheetUrl2: '', 
      bankId: 'vba', 
      accountNo: '8888942444224', accountName: 'TO TUAN KIET' 
    };
  });

  const [view, setView] = useState('list'); 
  const [activeTab, setActiveTab] = useState<'list1' | 'list2'>('list1');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showQr, setShowQr] = useState(false);
  const [onlyNonZalo, setOnlyNonZalo] = useState(false); 
  const [isListening, setIsListening] = useState(false);
  const [voiceText, setVoiceText] = useState('');

  const [quickIndex, setQuickIndex] = useState('');
  const [paidInput, setPaidInput] = useState('');

  const [editForm, setEditForm] = useState({ name: '', address: '', phone: '', stt: 0, oldIndex: 0, oldDebt: 0, isZalo: false });
  const [addForm, setAddForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollTargetId = useRef<string | null>(null);

  useEffect(() => {
    localStorage.setItem('water_data_final_v16', JSON.stringify(customers));
    localStorage.setItem('water_config_v16', JSON.stringify(config));
  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-blue-50');
          setTimeout(() => el.classList.remove('bg-blue-50'), 1500);
        }
        scrollTargetId.current = null;
      }, 100);
    }
  }, [view]);

  const filtered = useMemo(() => 
    customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      const s = searchQuery.toLowerCase();
      const matchSearch = String(c.name).toLowerCase().includes(s) || String(c.address).toLowerCase().includes(s) || String(c.phone).includes(s) || String(c.stt) === s;
      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return isCorrectTab && matchSearch && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt)
  , [customers, activeTab, searchQuery, onlyNonZalo]);

  const selectedCustomer = customers.find(c => c.id === selectedId);

  // Nhận diện giọng nói
  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Trình duyệt của bạn không hỗ trợ nhận diện giọng nói.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.interimResults = true;

    recognition.onstart = () => {
      setIsListening(true);
      setVoiceText('Đang nghe...');
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[event.results.length - 1][0].transcript;
      setVoiceText(transcript);
    };

    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => {
      setIsListening(false);
      processVoiceCommand(voiceText);
    };

    recognition.start();
  };

  const processVoiceCommand = (text: string) => {
    if (!text || text === 'Đang nghe...') return;

    // Regex: [Tên] + [số/số nước mới là] + [chỉ số] + [thu đủ/chưa thu]
    const regex = /(.+)\s+(?:số|số nước mới là|mới là)\s+(\d+)(?:,\s*(thu đủ|chưa thu))?/i;
    const match = text.match(regex);

    if (match) {
      const namePart = match[1].trim().toLowerCase();
      const newIdx = parseInt(match[2]);
      const statusPart = match[3] ? match[3].toLowerCase() : null;

      // Tìm khách hàng khớp tên nhất
      const found = customers.find(c => 
        c.listType === activeTab && 
        c.name.toLowerCase().includes(namePart)
      );

      if (found) {
        setCustomers(prev => prev.map(c => {
          if (c.id === found.id) {
            let paidValue = 0;
            if (statusPart === 'thu đủ') {
              const vol = (newIdx > 0 && newIdx >= c.oldIndex) ? (newIdx - c.oldIndex) : 0;
              paidValue = (vol * config.waterRate) + c.oldDebt;
            }
            return calculateRow({ ...c, newIndex: newIdx, paid: paidValue }, config.waterRate);
          }
          return c;
        }));
        scrollTargetId.current = found.id;
        setVoiceText(`Đã ghi: ${found.name} - ${newIdx}${statusPart ? ' - ' + statusPart : ''}`);
        setTimeout(() => setVoiceText(''), 3000);
      } else {
        alert(`Không tìm thấy khách hàng nào tên "${namePart}" trong danh sách này.`);
        setVoiceText('');
      }
    } else {
      alert("Câu lệnh chưa đúng. Ví dụ: 'Lê Minh Đồng số 1083, chưa thu'");
      setVoiceText('');
    }
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const currentIndex = filtered.findIndex(c => c.id === selectedId);
    let targetIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;

    if (targetIndex >= 0 && targetIndex < filtered.length) {
      const nextCust = filtered[targetIndex];
      setSelectedId(nextCust.id);
      setQuickIndex(nextCust.newIndex > 0 ? nextCust.newIndex.toString() : "");
      setPaidInput(nextCust.paid > 0 ? nextCust.paid.toString() : "");
    }
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      const ni = parseSafe(quickIndex);
      const pi = parseSafe(paidInput);
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Vui lòng nhập Link Script!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => {
          const stt = parseInt(item.stt);
          const localMatch = prev.find(p => p.stt === stt && p.listType === activeTab);
          return calculateRow({
            id: localMatch ? localMatch.id : `cust-${stt}-${activeTab}`,
            stt, name: item.name || `(STT ${stt} Trống tên)`,
            address: item.address || "", phone: item.phone || "",
            newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
            oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
            listType: activeTab, isZalo: !!item.isZalo
          }, config.waterRate);
        });
        return [...other, ...mapped];
      });
      alert(`Đồng bộ thành công!`);
    } catch (e: any) { alert(`Lỗi: ${e.message}`); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const newData = [...prev];
        imported.forEach(item => {
          const idx = newData.findIndex(c => c.stt === item.stt && c.listType === item.listType);
          if (idx !== -1) newData[idx] = { ...newData[idx], ...item, id: newData[idx].id };
          else newData.push(item);
        });
        return newData;
      });
      alert("Đã gộp Excel thành công!");
    } catch (err: any) { alert("Lỗi Excel: " + err.message); } finally { setIsSyncing(false); }
  };

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex);
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    const amountVnd = Math.round(currentUsage.total * 1000);
    const cleanName = selectedCustomer.name.normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/đ/g, "d").replace(/Đ/g, "D")
      .replace(/[^a-zA-Z0-9 ]/g, "");
    const description = `TT NUOC STT${selectedCustomer.stt} ${cleanName}`.toUpperCase();
    return `https://img.vietqr.io/image/${config.bankId}-${config.accountNo}-compact.png?amount=${amountVnd}&addInfo=${encodeURIComponent(description)}&accountName=${encodeURIComponent(config.accountName)}`;
  }, [selectedCustomer, currentUsage.total, config]);

  const handleCopyMessage = () => {
    if (!selectedCustomer) return;
    const msg = `BIÊN LAI NƯỚC\nDANH BỘ: ${activeTab === 'list1' ? '01' : '02'}\n-------------------------\nSTT: ${selectedCustomer.stt}\nKH: ${selectedCustomer.name.toUpperCase()}\nSỐ CŨ: ${selectedCustomer.oldIndex}\nSỐ MỚI: ${quickIndex || 0}\nTIÊU THỤ: ${currentUsage.vol} M³\nTIỀN NƯỚC: ${formatCurrency(currentUsage.amount)}\nNỢ CŨ: ${formatCurrency(selectedCustomer.oldDebt)}\n-------------------------\nTỔNG: ${formatCurrency(currentUsage.total)}\n\n${config.bankId.toUpperCase()}: ${config.accountNo}\n${config.accountName}`;

    navigator.clipboard.writeText(msg).then(() => {
      alert("Đã sao chép Biên lai mẫu gửi khách!");
    });
  };

  const toggleZalo = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: !c.isZalo } : c));
  };

  const handleAddCustomer = () => {
    const targetStt = addForm.stt;
    setCustomers(prev => {
      const shifted = prev.map(c => (c.listType === activeTab && c.stt >= targetStt) ? { ...c, stt: c.stt + 1 } : c);
      const rawNew = { id: `m-${Date.now()}`, ...addForm, newIndex: 0, paid: 0, listType: activeTab };
      return [...shifted, calculateRow(rawNew, config.waterRate)];
    });
    setAddForm({ name: '', address: '', phone: '', stt: targetStt + 1, oldIndex: 0, oldDebt: 0, isZalo: false });
    setView('list');
  };

  const startEditingCustomer = (c: any) => {
    setEditForm({ name: c.name, address: c.address, phone: c.phone || '', stt: c.stt, oldIndex: c.oldIndex, oldDebt: c.oldDebt, isZalo: !!c.isZalo });
    setView('edit_customer');
  };

  const handleUpdateCustomer = () => {
    if (!selectedId) return;
    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c));
    setView('detail');
  };

  const openZalo = (id: string, phone: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));
    if (!phone) {
      alert("Đã đánh dấu 'Đã vào Zalo'.\nVì không có số điện thoại trong App, bạn hãy mở Zalo và tìm tên khách hàng này nhé!");
      window.open(`https://zalo.me`, '_blank');
      return;
    }
    window.open(`https://zalo.me/${normalizePhoneForZalo(phone)}`, '_blank');
  };

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">
      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase tracking-tight">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
