            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Số điện thoại:</label><input className="w-full bg-slate-50 p-4 rounded-xl font-bold border-2 border-slate-100 outline-none focus:border-blue-500" type="tel" placeholder="09xxxx..." value={view === 'add_customer' ? addForm.phone : editForm.phone} onChange={e => view === 'add_customer' ? setAddForm({...addForm, phone: e.target.value}) : setEditForm({...editForm, phone: e.target.value})} /></div>
            {view === 'edit_customer' && (
              <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Nợ kỳ trước:</label><input className="w-full bg-slate-50 p-4 rounded-xl font-bold border-2 border-slate-100 outline-none focus:border-blue-500" type="number" value={editForm.oldDebt} onChange={e => setEditForm({...editForm, oldDebt: parseSafe(e.target.value)})} /></div>
