import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  CloudDownload, Settings, ChevronLeft, Search, Loader2, 
  X, Banknote, Save, Trash2, Pencil, Plus, Download, BarChart3, QrCode, Phone, Copy, Mic, FileJson, UploadCloud,
  MessageCircle, FileSpreadsheet, ExternalLink, ChevronRight, Sparkles
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { exportToExcel, parseExcelFile, normalizePhoneForZalo, formatCurrency } from './utils';
import { Customer } from './types';

const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('water_data_final_v16');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState(() => {
    const saved = localStorage.getItem('water_config_v16');
    return saved ? JSON.parse(saved) : { 
      waterRate: 16.5, sheetUrl1: '', sheetUrl2: '', 
      bankId: 'vba', 
      accountNo: '8888942444224', accountName: 'TO TUAN KIET' 
    };
  });

  const [view, setView] = useState('list'); 
  const [activeTab, setActiveTab] = useState<'list1' | 'list2'>('list1');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showQr, setShowQr] = useState(false);
  const [onlyNonZalo, setOnlyNonZalo] = useState(false); 
  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);
  const [voiceText, setVoiceText] = useState('');

  const [quickIndex, setQuickIndex] = useState('');
  const [paidInput, setPaidInput] = useState('');

  const [editForm, setEditForm] = useState({ name: '', address: '', phone: '', stt: 0, oldIndex: 0, oldDebt: 0, isZalo: false });
  const [addForm, setAddForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollTargetId = useRef<string | null>(null);

  useEffect(() => {
    localStorage.setItem('water_data_final_v16', JSON.stringify(customers));
    localStorage.setItem('water_config_v16', JSON.stringify(config));
  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-blue-50');
          setTimeout(() => el.classList.remove('bg-blue-50'), 1500);
        }
        scrollTargetId.current = null;
      }, 100);
    }
  }, [view]);

  const filtered = useMemo(() => 
    customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      const s = searchQuery.toLowerCase();
      const matchSearch = String(c.name).toLowerCase().includes(s) || String(c.address).toLowerCase().includes(s) || String(c.phone).includes(s) || String(c.stt) === s;
      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return isCorrectTab && matchSearch && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt)
  , [customers, activeTab, searchQuery, onlyNonZalo]);

  const selectedCustomer = customers.find(c => c.id === selectedId);

  // Xử lý AI parsing
  const parseWithAI = async (text: string) => {
    setIsProcessingAI(true);
    setVoiceText(`AI đang hiểu: "${text}"...`);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Phân tích câu nói ghi nước sau và trả về JSON: "${text}"`,
        config: {
          systemInstruction: "Bạn là trợ lý ghi nước chuyên nghiệp. Trích xuất thông tin: name (tên khách hàng), newIndex (số nước mới, dạng số), isPaid (boolean: true nếu đã thu tiền hoặc đã trả, false nếu chưa thu hoặc nợ). Ví dụ: 'Đồng 1083 chưa thu' -> {\"name\": \"Đồng\", \"newIndex\": 1083, \"isPaid\": false}. Trả về định dạng JSON thuần.",
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              newIndex: { type: Type.NUMBER },
              isPaid: { type: Type.BOOLEAN }
            },
            required: ["name", "newIndex", "isPaid"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      if (result.name && result.newIndex) {
        applyVoiceResult(result);
      } else {
        setVoiceText("Không rõ thông tin khách hoặc số nước.");
      }
    } catch (error) {
      console.error(error);
      setVoiceText("Lỗi xử lý AI. Vui lòng thử lại.");
    } finally {
      setIsProcessingAI(false);
    }
  };

  const applyVoiceResult = (result: {name: string, newIndex: number, isPaid: boolean}) => {
    const searchName = result.name.toLowerCase();
    const found = customers.find(c => 
      c.listType === activeTab && 
      (c.name.toLowerCase().includes(searchName) || searchName.includes(c.name.toLowerCase()))
    );

    if (found) {
      setCustomers(prev => prev.map(c => {
        if (c.id === found.id) {
          let paidValue = 0;
          if (result.isPaid) {
            const vol = (result.newIndex > 0 && result.newIndex >= c.oldIndex) ? (result.newIndex - c.oldIndex) : 0;
            paidValue = (vol * config.waterRate) + c.oldDebt;
          }
          return calculateRow({ ...c, newIndex: result.newIndex, paid: paidValue }, config.waterRate);
        }
        return c;
      }));
      scrollTargetId.current = found.id;
      setVoiceText(`✅ Đã ghi: ${found.name} - ${result.newIndex} (${result.isPaid ? 'Thu đủ' : 'Chưa thu'})`);
      setTimeout(() => setVoiceText(''), 4000);
    } else {
      setVoiceText(`❌ Không tìm thấy ai tên "${result.name}"`);
    }
  };

  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Trình duyệt không hỗ trợ nhận diện giọng nói.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.interimResults = false;

    recognition.onstart = () => {
      setIsListening(true);
      setVoiceText('Đang nghe...');
    };

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      parseWithAI(transcript);
    };

    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => setIsListening(false);

    recognition.start();
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const currentIndex = filtered.findIndex(c => c.id === selectedId);
    let targetIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;

    if (targetIndex >= 0 && targetIndex < filtered.length) {
      const nextCust = filtered[targetIndex];
      setSelectedId(nextCust.id);
      setQuickIndex(nextCust.newIndex > 0 ? nextCust.newIndex.toString() : "");
      setPaidInput(nextCust.paid > 0 ? nextCust.paid.toString() : "");
    }
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      const ni = parseSafe(quickIndex);
      const pi = parseSafe(paidInput);
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Vui lòng nhập Link Script!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => {
          const stt = parseInt(item.stt);
          const localMatch = prev.find(p => p.stt === stt && p.listType === activeTab);
          return calculateRow({
            id: localMatch ? localMatch.id : `cust-${stt}-${activeTab}`,
            stt, name: item.name || `(STT ${stt} Trống tên)`,
            address: item.address || "", phone: item.phone || "",
            newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
            oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
            listType: activeTab, isZalo: !!item.isZalo
          }, config.waterRate);
        });
        return [...other, ...mapped];
      });
      alert("Đồng bộ thành công!");
    } catch (e: any) { alert(`Lỗi: ${e.message}`); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const newData = [...prev];
        imported.forEach(item => {
          const idx = newData.findIndex(c => c.stt === item.stt && c.listType === item.listType);
          if (idx !== -1) newData[idx] = { ...newData[idx], ...item, id: newData[idx].id };
          else newData.push(item);
        });
        return newData;
      });
      alert("Đã gộp Excel thành công!");
    } catch (err: any) { alert("Lỗi Excel: " + err.message); } finally { setIsSyncing(false); }
  };

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex);
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    const amountVnd = Math.round(currentUsage.total * 1000);
    const cleanName = selectedCustomer.name.normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/đ/g, "d").replace(/Đ/g, "D")
      .replace(/[^a-zA-Z0-9 ]/g, "");
    const description = `TT NUOC STT${selectedCustomer.stt} ${cleanName}`.toUpperCase();
    return `https://img.vietqr.io/image/${config.bankId}-${config.accountNo}-compact.png?amount=${amountVnd}&addInfo=${encodeURIComponent(description)}&accountName=${encodeURIComponent(config.accountName)}`;
  }, [selectedCustomer, currentUsage.total, config]);

  const handleCopyMessage = () => {
    if (!selectedCustomer) return;
    const msg = `BIÊN LAI NƯỚC\nDANH BỘ: ${activeTab === 'list1' ? '01' : '02'}\n-------------------------\nSTT: ${selectedCustomer.stt}\nKH: ${selectedCustomer.name.toUpperCase()}\nSỐ CŨ: ${selectedCustomer.oldIndex}\nSỐ MỚI: ${quickIndex || 0}\nTIÊU THỤ: ${currentUsage.vol} M³\nTIỀN NƯỚC: ${formatCurrency(currentUsage.amount)}\nNỢ CŨ: ${formatCurrency(selectedCustomer.oldDebt)}\n-------------------------\nTỔNG: ${formatCurrency(currentUsage.total)}\n\n${config.bankId.toUpperCase()}: ${config.accountNo}\n${config.accountName}`;

    navigator.clipboard.writeText(msg).then(() => {
      alert("Đã sao chép Biên lai mẫu gửi khách!");
    });
  };

  const toggleZalo = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: !c.isZalo } : c));
  };

  const handleAddCustomer = () => {
    const targetStt = addForm.stt;
    setCustomers(prev => {
      const shifted = prev.map(c => (c.listType === activeTab && c.stt >= targetStt) ? { ...c, stt: c.stt + 1 } : c);
      const rawNew = { id: `m-${Date.now()}`, ...addForm, newIndex: 0, paid: 0, listType: activeTab };
      return [...shifted, calculateRow(rawNew, config.waterRate)];
    });
    setAddForm({ name: '', address: '', phone: '', stt: targetStt + 1, oldIndex: 0, oldDebt: 0, isZalo: false });
    setView('list');
  };

  const startEditingCustomer = (c: any) => {
    setEditForm({ name: c.name, address: c.address, phone: c.phone || '', stt: c.stt, oldIndex: c.oldIndex, oldDebt: c.oldDebt, isZalo: !!c.isZalo });
    setView('edit_customer');
  };

  const handleUpdateCustomer = () => {
    if (!selectedId) return;
    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c));
    setView('detail');
  };

  const openZalo = (id: string, phone: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));
    if (!phone) {
      alert("Đã đánh dấu 'Đã vào Zalo'.\nVì không có số điện thoại trong App, bạn hãy mở Zalo và tìm tên khách hàng này nhé!");
      window.open(`https://zalo.me`, '_blank');
      return;
    }
    window.open(`https://zalo.me/${normalizePhoneForZalo(phone)}`, '_blank');
  };

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">
      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase tracking-tight">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl relative ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}>
                <MessageCircle size={22}/>
                {stats.noZalo > 0 && !onlyNonZalo && <span className="absolute -top-0.5 -right-0.5 bg-red-600 text-white text-[8px] font-black w-3.5 h-3.5 rounded-full flex items-center justify-center">{stats.noZalo}</span>}
              </button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('add_customer')} className="p-2 text-slate-600"><Plus size={22}/></button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2">
            <div className="flex gap-2">
              <div className="relative flex-1">
                <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT, SĐT..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
              </div>
              <button 
                onClick={startListening} 
                disabled={isProcessingAI}
                className={`p-3 rounded-xl shadow-sm transition-all flex items-center justify-center border ${isListening ? 'bg-red-500 text-white animate-pulse border-red-500' : isProcessingAI ? 'bg-blue-100 text-blue-600 border-blue-200' : 'bg-white text-red-500 active:bg-red-50 border-slate-200'}`}
              >
                {isProcessingAI ? <Loader2 size={20} className="animate-spin"/> : <Mic size={20}/>}
              </button>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600 active:bg-blue-50 transition-all border-slate-200"><BarChart3 size={20}/></button>
            </div>

            {voiceText && (
              <div className="bg-slate-900/90 backdrop-blur-md text-white p-3 rounded-2xl text-[11px] font-black italic shadow-2xl animate-in fade-in slide-in-from-top-2 duration-300 flex items-center gap-2">
                {isProcessingAI ? <Sparkles size={14} className="text-blue-400 animate-bounce"/> : "🎙️"} 
                <span className="flex-1">{voiceText}</span>
              </div>
            )}
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28 scroll-smooth">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { 
                setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); 
                setPaidInput(c.paid > 0 ? c.paid.toString() : ""); setView('detail'); 
              }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all scroll-mt-24">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => toggleZalo(c.id, e)} className={`p-1.5 rounded-full border transition-all ${c.isZalo ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'text-slate-300 border-slate-100'}`}><MessageCircle size={14} /></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className={`font-black uppercase text-[15px] truncate leading-tight ${c.isZalo ? 'text-blue-700' : 'text-slate-900'} ${c.name.includes('Trống tên') ? 'text-slate-300 italic font-normal' : ''}`}>{c.name}</h3>
                    <p className="text-[11px] text-slate-500 truncate font-bold mb-1.5">{c.address || '---'}</p>
                    <div className="flex items-center gap-2">
                      {c.phone && <a href={`tel:${c.phone}`} onClick={e => e.stopPropagation()} className="flex items-center gap-1 text-[11px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100"><Phone size={12}/> GỌI</a>}
                      <button onClick={(e) => openZalo(c.id, c.phone, e)} className="flex items-center gap-1 text-[11px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg border border-blue-100"><MessageCircle size={12}/> ZALO</button>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className={`font-black text-[17px] tracking-tighter ${c.status === 'paid' ? 'text-emerald-700' : 'text-rose-700'}`}>{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 && <div className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded mt-1 shadow-sm">Số: {c.newIndex}</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${activeTab === 'list1' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${activeTab === 'list2' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4 animate-in slide-in-from-right duration-200 overflow-hidden">
          <header className="flex justify-between items-center mb-6 shrink-0">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400 active:scale-90"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border shadow-inner">
                <button 
                  onClick={() => navigateDetail('prev')} 
                  disabled={filtered.findIndex(c => c.id === selectedId) === 0}
