import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  CloudDownload, Settings, ChevronLeft, Search, Loader2, 
  X, Banknote, Save, Trash2, Pencil, Plus, Download, BarChart3, QrCode, Phone, Copy, Mic, FileJson, UploadCloud,
  MessageCircle, FileSpreadsheet, ExternalLink, ChevronRight, Sparkles, Landmark, CheckCheck
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { exportToExcel, parseExcelFile, normalizePhoneForZalo, formatCurrency } from './utils';
import { Customer } from './types';

const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('water_data_final_v16');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState(() => {
    const saved = localStorage.getItem('water_config_v16');
    return saved ? JSON.parse(saved) : { 
      waterRate: 16.5, sheetUrl1: '', sheetUrl2: '', 
      bankId: 'vba', 
      accountNo: '8888942444224', accountName: 'TO TUAN KIET' 
    };
  });

