        contents: `Phân tích lịch sử giao dịch sau: "${bankHistoryText}"`,
        config: {
          systemInstruction: `Tìm các giao dịch TT NUOC, STT hoặc tên người dùng. Trả về JSON mảng: [{stt: number, name: string, amount_k: number}].`,
          responseMimeType: "application/json"
        }
      });
      const matches = JSON.parse(response.text || "[]");
      setCustomers(prev => prev.map(c => {
        if (c.listType !== activeTab) return c;
        const match = matches.find((m: any) => (m.stt && m.stt === c.stt) || (m.name && c.name.toLowerCase().includes(m.name.toLowerCase())));
        if (match) {
          return calculateRow({ ...c, paid: match.amount_k }, config.waterRate);
        }
        return c;
      }));
    } catch (error) { console.error(error); } finally { setIsProcessingAI(false); }
  };

  const parseWithAI = async (text: string) => {
    setIsProcessingAI(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Ghi nước: "${text}"`,
        config: { systemInstruction: "Trích JSON: {name, newIndex, isPaid}", responseMimeType: "application/json" }
      });
      const result = JSON.parse(response.text || "{}");
      if (result.name && result.newIndex) applyVoiceResult(result);
    } catch (e) {} finally { setIsProcessingAI(false); }
  };

  const applyVoiceResult = (result: any) => {
    const found = customers.find(c => c.listType === activeTab && c.name.toLowerCase().includes(result.name.toLowerCase()));
    if (found) {
      setCustomers(prev => prev.map(c => c.id === found.id ? calculateRow({ ...c, newIndex: result.newIndex }, config.waterRate) : c));
      scrollTargetId.current = found.id;
      setView('list');
    }
  };

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Vui lòng nhập Link Script!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt} Trống)`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo
        }, config.waterRate));
        return [...other, ...mapped];
      });
      alert("Đồng bộ thành công!");
    } catch (e: any) { alert(`Lỗi: ${e.message}`); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const newData = [...prev];
        imported.forEach(item => {
          const idx = newData.findIndex(c => c.stt === item.stt && c.listType === item.listType);
          if (idx !== -1) newData[idx] = { ...newData[idx], ...item };
          else newData.push(item);
        });
        return newData;
      });
      alert("Đã gộp Excel thành công!");
    } catch (err: any) { alert("Lỗi Excel: " + err.message); } finally { setIsSyncing(false); }
  };

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex);
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    const amountVnd = Math.round(currentUsage.total * 1000);
    const cleanName = selectedCustomer.name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9 ]/g, "");
    return `https://img.vietqr.io/image/${config.bankId}-${config.accountNo}-compact.png?amount=${amountVnd}&addInfo=${encodeURIComponent('TT NUOC STT' + selectedCustomer.stt)}&accountName=${encodeURIComponent(config.accountName)}`;
  }, [selectedCustomer, currentUsage.total, config]);

  const openZalo = (id: string, phone: string) => {
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));
    const normalized = normalizePhoneForZalo(phone);
    window.location.assign(normalized ? `https://zalo.me/${normalized}` : `https://zalo.me`);
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const currentIndex = filtered.findIndex(c => c.id === selectedId);
    let targetIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (targetIndex >= 0 && targetIndex < filtered.length) {
      const nextCust = filtered[targetIndex];
      setSelectedId(nextCust.id);
      setQuickIndex(nextCust.newIndex > 0 ? nextCust.newIndex.toString() : "");
      setPaidInput(nextCust.paid > 0 ? nextCust.paid.toString() : "");
    }
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      const ni = parseSafe(quickIndex);
      const pi = parseSafe(paidInput);
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  const handleAddCustomer = () => {
    const newCust = calculateRow({
      id: `cust-custom-${Date.now()}`,
      ...addForm,
      listType: activeTab,
      newIndex: 0,
      paid: 0
    }, config.waterRate);
    setCustomers(prev => [...prev, newCust]);
    setShowAddModal(false);
    setAddForm({ name: '', address: '', phone: '', stt: stats.totalCust + 2, oldIndex: 0, oldDebt: 0, isZalo: false });
  };

  const handleSaveEdit = () => {
    if (!selectedId) return;
    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c));
    setView('detail');
  };

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">
      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase tracking-tight">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setShowAddModal(true)} className="p-2 text-blue-600 active:scale-90"><Plus size={24}/></button>
              <button onClick={() => setShowBankCheck(true)} className="p-2 text-emerald-600 active:scale-90"><Landmark size={22}/></button>
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl relative ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}>
                <MessageCircle size={22}/>
                {stats.noZalo > 0 && !onlyNonZalo && <span className="absolute -top-0.5 -right-0.5 bg-red-600 text-white text-[8px] font-black w-3.5 h-3.5 rounded-full flex items-center justify-center">{stats.noZalo}</span>}
              </button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2">
            <div className="flex gap-2">
              <div className="relative flex-1">
                <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT, SĐT..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
              </div>
              <button onClick={() => { const sr = new (window as any).webkitSpeechRecognition(); sr.lang='vi-VN'; sr.onstart=()=>setIsListening(true); sr.onresult=(e:any)=>parseWithAI(e.results[0][0].transcript); sr.onend=()=>setIsListening(false); sr.start(); }} disabled={isProcessingAI} className={`p-3 rounded-xl shadow-sm transition-all flex items-center justify-center border ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-red-500'}`}>
                {isProcessingAI ? <Loader2 size={20} className="animate-spin"/> : <Mic size={20}/>}
              </button>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600 active:bg-blue-50 transition-all border-slate-200"><BarChart3 size={20}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28 scroll-smooth">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? c.paid.toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all scroll-mt-24">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border transition-all ${c.isZalo ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'text-slate-300 border-slate-100'}`}><MessageCircle size={14} /></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className={`font-black uppercase text-[15px] truncate leading-tight ${c.isZalo ? 'text-blue-700' : 'text-slate-900'}`}>{c.name}</h3>
                    <p className="text-[11px] text-slate-500 truncate font-bold mb-1.5">{c.address || '---'}</p>
                    <div className="flex items-center gap-2">
                      {c.phone && <a href={`tel:${c.phone}`} onClick={e => e.stopPropagation()} className="flex items-center gap-1 text-[11px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg border border-emerald-100"><Phone size={12}/> GỌI</a>}
                      <button onClick={(e) => {e.stopPropagation(); openZalo(c.id, c.phone);}} className="flex items-center gap-1 text-[11px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg border border-blue-100"><MessageCircle size={12}/> ZALO</button>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className={`font-black text-[17px] tracking-tighter ${c.status === 'paid' ? 'text-emerald-700' : 'text-rose-700'}`}>{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 && <div className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded mt-1 shadow-sm">Số: {c.newIndex}</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          {showAddModal && (
            <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl animate-in zoom-in-95 duration-200 overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Thêm khách hàng</h2><button onClick={() => setShowAddModal(false)}><X/></button></div>
                <div className="space-y-4">
                  <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
                  <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
                  <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Số điện thoại" value={addForm.phone} onChange={e => setAddForm({...addForm, phone: e.target.value})} />
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1"><label className="text-[10px] font-black">STT</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value)})} /></div>
                    <div className="space-y-1"><label className="text-[10px] font-black">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value)})} /></div>
                  </div>
                  <div className="space-y-1"><label className="text-[10px] font-black">Nợ cũ (K)</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={addForm.oldDebt} onChange={e => setAddForm({...addForm, oldDebt: parseFloat(e.target.value)})} /></div>
                  <button onClick={handleAddCustomer} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-4">Tạo mới</button>
                </div>
              </div>
            </div>
          )}

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${activeTab === 'list1' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${activeTab === 'list2' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4 animate-in slide-in-from-right duration-200 overflow-hidden">
          <header className="flex justify-between items-center mb-6 shrink-0">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400 active:text-blue-600"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400 active:text-blue-600"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => { setEditForm({ name: selectedCustomer.name, address: selectedCustomer.address, phone: selectedCustomer.phone, stt: selectedCustomer.stt, oldIndex: selectedCustomer.oldIndex, oldDebt: selectedCustomer.oldDebt, isZalo: !!selectedCustomer.isZalo }); setView('edit_customer'); }} className="p-3 bg-slate-50 rounded-full border shadow-sm"><Pencil size={20}/></button>
              <button onClick={() => { navigator.clipboard.writeText(`STT: ${selectedCustomer.stt}\nKH: ${selectedCustomer.name}\nTỔNG: ${formatCurrency(currentUsage.total)}`); alert("Đã copy!"); }} className="p-3 bg-slate-50 rounded-full border shadow-sm"><Copy size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>
          <div className="flex-1 space-y-6 overflow-y-auto px-2">
            <div className="border-l-4 border-blue-600 pl-4">
              <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded">STT: {selectedCustomer.stt}</span>
              <h2 className="font-black uppercase text-xl text-slate-900">{selectedCustomer.name}</h2>
              <p className="text-sm text-slate-500 italic mb-3">{selectedCustomer.address}</p>
            </div>
            <div className="bg-slate-50 rounded-3xl p-6 border shadow-inner">
              <div className="grid grid-cols-2 gap-4 text-center">
                <div><p className="text-[10px] font-black text-slate-400 uppercase">Số cũ</p><div className="text-4xl font-black">{selectedCustomer.oldIndex}</div></div>
                <div><p className="text-[10px] font-black text-blue-600 uppercase">Số mới</p><input autoFocus type="number" className="w-full text-center text-4xl font-black text-blue-600 bg-transparent outline-none" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} /></div>
              </div>
            </div>
            <div className="space-y-3 bg-white border p-5 rounded-3xl shadow-sm border-slate-100 text-lg">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(currentUsage.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ cũ:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t border-dashed my-2"></div>
              <div className="flex justify-between items-center font-black text-blue-600"><span>Tổng cộng:</span><span className="text-3xl tracking-tighter">{formatCurrency(currentUsage.total)}</span></div>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 pt-4 border-t shrink-0">
            <button onClick={() => { 
              const fullAmt = currentUsage.total.toString();
              setPaidInput(fullAmt); 
              // Cập nhật ngay lập tức vào state để tránh lỗi 0 đồng ngoài danh sách
              const ni = parseSafe(quickIndex);
              const pi = parseSafe(fullAmt);
              setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
              scrollTargetId.current = selectedId; 
              setTimeout(() => setView('list'), 50); 
            }} className="bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-lg">Thu đủ</button>
            <button onClick={() => { scrollTargetId.current = selectedId; setView('list'); }} className="bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Lưu & Về</button>
          </div>
          {showQr && (
            <div className="absolute inset-0 bg-white/95 z-[60] flex flex-col items-center justify-center p-6 animate-in fade-in duration-200">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border-2 w-full text-center">
                <p className="font-black text-blue-600 uppercase mb-4 italic">Mã thanh toán Agribank</p>
                <img src={qrUrl} className="w-full aspect-square object-contain" alt="QR" />
                <button onClick={() => setShowQr(false)} className="mt-8 w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase">Đóng mã QR</button>
              </div>
            </div>
          )}
        </div>
      )}

      {view === 'edit_customer' && (
        <div className="h-full bg-white p-6 animate-in slide-in-from-bottom duration-200 overflow-y-auto">
          <header className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Sửa thông tin</h2><button onClick={() => setView('detail')}><X/></button></header>
          <div className="space-y-4 pb-10">
            <div className="space-y-1"><label className="text-[10px] font-black">Họ và Tên</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black">Địa chỉ</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.address} onChange={e => setEditForm({...editForm, address: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black">SĐT</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.phone} onChange={e => setEditForm({...editForm, phone: e.target.value})} /></div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1"><label className="text-[10px] font-black">STT</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.stt} onChange={e => setEditForm({...editForm, stt: parseInt(e.target.value)})} /></div>
              <div className="space-y-1"><label className="text-[10px] font-black">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldIndex} onChange={e => setEditForm({...editForm, oldIndex: parseFloat(e.target.value)})} /></div>
            </div>
            <div className="space-y-1"><label className="text-[10px] font-black">Nợ cũ (K)</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldDebt} onChange={e => setEditForm({...editForm, oldDebt: parseFloat(e.target.value)})} /></div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => { if(confirm("Xóa khách hàng này?")) { setCustomers(prev => prev.filter(c => c.id !== selectedId)); setView('list'); } }} className="bg-rose-50 text-rose-600 p-4 rounded-2xl border border-rose-100 active:scale-95"><Trash2/></button>
              <button onClick={handleSaveEdit} className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Lưu thay đổi</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full active:scale-90"><X size={20}/></button></header>
          <div className="space-y-5 pb-20">
            <div className="bg-white border p-6 rounded-3xl space-y-4 shadow-sm border-slate-100">
              <h3 className="text-[11px] font-black text-slate-400 uppercase text-center tracking-widest">Đồng bộ dữ liệu</h3>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 bg-blue-600 text-white p-4 rounded-2xl shadow-lg active:scale-95"><UploadCloud size={24}/> <span className="text-[10px] font-black uppercase">Gộp Excel</span></button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `SaoLuu_${activeTab}`)} className="flex flex-col items-center gap-2 border-2 border-blue-600 text-blue-600 p-4 rounded-2xl shadow-sm active:scale-95"><FileSpreadsheet size={24}/> <span className="text-[10px] font-black uppercase">Xuất Excel</span></button>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
            </div>

            <div className="space-y-4">
