            <div className="bg-emerald-50 p-6 rounded-3xl text-center"><p className="text-[10px] font-black uppercase text-emerald-400 mb-1">Đã ghi</p><p className="text-3xl font-black text-emerald-600">{stats.recorded}</p></div>
