             <div className="flex justify-between font-bold text-blue-600 uppercase text-sm italic"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount || 0)}</span></div>
             <div className="flex justify-between font-bold text-rose-600 uppercase text-sm italic"><span>Nợ kỳ trước:</span><span>{formatCurrency(stats.totalOldDebt || 0)}</span></div>
          </div>
