  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-blue-50');
          setTimeout(() => el.classList.remove('bg-blue-50'), 1500);
        }
        scrollTargetId.current = null;
      }, 100);
    }
  }, [view]);

  const filtered = useMemo(() => 
    customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      const s = searchQuery.toLowerCase();
      const matchSearch = String(c.name).toLowerCase().includes(s) || String(c.address).toLowerCase().includes(s) || String(c.phone).includes(s) || String(c.stt) === s;
      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return isCorrectTab && matchSearch && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt)
  , [customers, activeTab, searchQuery, onlyNonZalo]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const selectedCustomer = customers.find(c => c.id === selectedId);

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Vui lòng nhập Link Script!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt} Trống)`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo
        }, config.waterRate));
        return [...other, ...mapped];
      });
      alert("Đồng bộ thành công!");
    } catch (e: any) { alert(`Lỗi: ${e.message}`); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const newData = [...prev];
        imported.forEach(item => {
          const idx = newData.findIndex(c => c.stt === item.stt && c.listType === item.listType);
          if (idx !== -1) newData[idx] = { ...newData[idx], ...item };
          else newData.push(item);
        });
        return newData;
      });
      alert("Đã gộp Excel thành công!");
    } catch (err: any) { alert("Lỗi Excel: " + err.message); } finally { setIsSyncing(false); }
  };

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex);
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const qrTransferInfo = useMemo(() => {
    if (!selectedCustomer) return { amount: 0, content: '' };
    const cleanName = selectedCustomer.name.normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D")
      .replace(/[^a-zA-Z0-9 ]/g, "").toUpperCase();
    return {
      amount: Math.round(currentUsage.total * 1000),
      content: `TT NUOC STT${selectedCustomer.stt} ${cleanName}`
    };
  }, [selectedCustomer, currentUsage.total]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    return `https://img.vietqr.io/image/${config.bankId}-${config.accountNo}-compact.png?amount=${qrTransferInfo.amount}&addInfo=${encodeURIComponent(qrTransferInfo.content)}&accountName=${encodeURIComponent(config.accountName)}`;
  }, [selectedCustomer, qrTransferInfo, config]);

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const currentIndex = filtered.findIndex(c => c.id === selectedId);
    let targetIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (targetIndex >= 0 && targetIndex < filtered.length) {
      const nextCust = filtered[targetIndex];
      setSelectedId(nextCust.id);
      setQuickIndex(nextCust.newIndex > 0 ? nextCust.newIndex.toString() : "");
      setPaidInput(nextCust.paid > 0 ? nextCust.paid.toString() : "");
    }
  };

  const saveCurrentCustomer = (isThuDu: boolean = false) => {
    if (!selectedId) return;
    const fullAmt = isThuDu ? currentUsage.total.toString() : paidInput;
    const ni = parseSafe(quickIndex);
    const pi = parseSafe(fullAmt);
    setCustomers(prev => prev.map(c => 
      c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c
    ));
    scrollTargetId.current = selectedId;
    setView('list');
  };

  const handleVoiceRecord = () => {
    const sr = new (window as any).webkitSpeechRecognition();
    sr.lang = 'vi-VN';
    sr.onstart = () => setIsListening(true);
    sr.onresult = async (e: any) => {
      const text = e.results[0][0].transcript;
      setIsProcessingAI(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Ghi nước: "${text}"`,
          config: { systemInstruction: "Trích JSON: {name, newIndex}", responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || "{}");
        if (result.name && result.newIndex) {
          const found = customers.find(c => c.listType === activeTab && c.name.toLowerCase().includes(result.name.toLowerCase()));
          if (found) {
            setCustomers(prev => prev.map(c => c.id === found.id ? calculateRow({ ...c, newIndex: result.newIndex }, config.waterRate) : c));
            scrollTargetId.current = found.id;
          }
        }
      } catch (err) {} finally { setIsProcessingAI(false); }
    };
    sr.onend = () => setIsListening(false);
    sr.start();
  };

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl">
      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase">{activeTab === 'list1' ? 'Bộ 01' : 'Bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setShowAddModal(true)} className="p-2 text-blue-600"><Plus size={24}/></button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 flex gap-2">
            <div className="relative flex-1">
              <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
            </div>
            <button onClick={handleVoiceRecord} className={`p-3 rounded-xl border ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-red-500'}`}>
              <Mic size={20}/>
            </button>
            <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl text-blue-600"><BarChart3 size={20}/></button>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28 scroll-smooth">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? c.paid.toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border ${c.isZalo ? 'bg-blue-600 text-white' : 'text-slate-300'}`}><MessageCircle size={14}/></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="font-black uppercase text-[15px] truncate text-slate-900">{c.name}</h3>
                    <p className="text-[11px] text-slate-500 truncate mb-1.5">{c.address || '---'}</p>
                    <div className="flex items-center gap-2">
                      <button onClick={(e) => {e.stopPropagation(); const normalized = normalizePhoneForZalo(c.phone); window.location.assign(`https://zalo.me/${normalized}`);}} className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg">ZALO</button>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className={`font-black text-[17px] ${c.status === 'paid' ? 'text-emerald-700' : 'text-rose-700'}`}>{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 && <div className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded mt-1">Số: {c.newIndex}</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 border p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list1' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list2' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4 animate-in slide-in-from-right duration-200">
          <header className="flex justify-between items-center mb-6 shrink-0">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              {/* Fix: Explicitly map required fields from selectedCustomer to match editForm state type and handle optional isZalo */}
              <button onClick={() => { 
                setEditForm({ 
                  name: selectedCustomer.name,
                  address: selectedCustomer.address,
                  phone: selectedCustomer.phone,
                  stt: selectedCustomer.stt,
                  oldIndex: selectedCustomer.oldIndex,
                  oldDebt: selectedCustomer.oldDebt,
                  isZalo: !!selectedCustomer.isZalo
                }); 
                setView('edit_customer'); 
              }} className="p-3 bg-slate-50 rounded-full border"><Pencil size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>
          <div className="flex-1 space-y-6 overflow-y-auto">
            <div className="border-l-4 border-blue-600 pl-4">
              <h2 className="font-black uppercase text-xl">{selectedCustomer.name}</h2>
              <p className="text-sm text-slate-500 italic">{selectedCustomer.address}</p>
            </div>
            <div className="bg-slate-50 rounded-3xl p-6 border shadow-inner text-center">
              <div className="grid grid-cols-2 gap-4">
                <div><p className="text-[10px] font-black uppercase text-slate-400">Số cũ</p><div className="text-4xl font-black">{selectedCustomer.oldIndex}</div></div>
                <div><p className="text-[10px] font-black uppercase text-blue-600">Số mới</p><input autoFocus type="number" className="w-full text-center text-4xl font-black text-blue-600 bg-transparent outline-none" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} /></div>
              </div>
            </div>
            <div className="space-y-3 bg-white border p-5 rounded-3xl shadow-sm text-lg">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(currentUsage.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ cũ:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t border-dashed my-2"></div>
              <div className="flex justify-between items-center font-black text-blue-600"><span>Tổng cộng:</span><span className="text-3xl tracking-tighter">{formatCurrency(currentUsage.total)}</span></div>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 pt-4 border-t shrink-0">
            <button onClick={() => saveCurrentCustomer(true)} className="bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase">Thu đủ</button>
            <button onClick={() => saveCurrentCustomer(false)} className="bg-blue-600 text-white py-4 rounded-2xl font-black uppercase">Lưu & Về</button>
          </div>
          {showQr && (
            <div className="fixed inset-0 bg-white/98 z-[60] flex flex-col items-center justify-center p-6">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border-2 w-full max-w-sm text-center">
                <p className="font-black text-blue-600 uppercase mb-2 italic">Thanh toán Agribank</p>
                <div className="mb-4 bg-blue-50 p-3 rounded-2xl border text-left text-[11px] space-y-1">
                   <div className="flex justify-between"><span>Số tiền:</span><span className="text-blue-700 font-black">{new Intl.NumberFormat('vi-VN').format(qrTransferInfo.amount)} VNĐ</span></div>
                   <div className="flex justify-between"><span>Nội dung:</span><span className="text-slate-900 font-black">{qrTransferInfo.content}</span></div>
                </div>
                <img src={qrUrl} className="w-full aspect-square object-contain mb-4" alt="QR" />
                <button onClick={() => setShowQr(false)} className="w-full bg-[#111827] text-white py-4 rounded-2xl font-black uppercase">Đóng mã QR</button>
              </div>
            </div>
          )}
        </div>
      )}

      {view === 'edit_customer' && (
        <div className="h-full bg-white p-6 animate-in slide-in-from-bottom duration-200 overflow-y-auto">
          <header className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Sửa thông tin</h2><button onClick={() => setView('detail')}><X/></button></header>
          <div className="space-y-4">
            <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} />
            <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={editForm.address} onChange={e => setEditForm({...editForm, address: e.target.value})} />
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1"><label className="text-[10px] font-black">STT</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.stt} onChange={e => setEditForm({...editForm, stt: parseInt(e.target.value)})} /></div>
              <div className="space-y-1"><label className="text-[10px] font-black">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldIndex} onChange={e => setEditForm({...editForm, oldIndex: parseFloat(e.target.value)})} /></div>
            </div>
            <div className="space-y-1"><label className="text-[10px] font-black">Nợ cũ (K)</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldDebt} onChange={e => setEditForm({...editForm, oldDebt: parseFloat(e.target.value)})} /></div>
            <button onClick={() => { setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c)); setView('detail'); }} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase">Lưu thay đổi</button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Thêm khách hàng</h2><button onClick={() => setShowAddModal(false)}><X/></button></div>
            <div className="space-y-4">
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="STT" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value)})} />
                <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Số cũ" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value)})} />
              </div>
              <button onClick={() => { const nc = calculateRow({ id: `custom-${Date.now()}`, ...addForm, listType: activeTab, newIndex: 0, paid: 0 }, config.waterRate); setCustomers(prev => [...prev, nc]); setShowAddModal(false); }} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase">Tạo mới</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic">Cấu hình</h2><button onClick={() => setView('list')}><X/></button></header>
          <div className="space-y-5">
             <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 bg-blue-600 text-white p-4 rounded-2xl"><UploadCloud/> <span className="text-[10px] font-black uppercase">Gộp Excel</span></button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `SaoLuu_${activeTab}`)} className="flex flex-col items-center gap-2 border-2 border-blue-600 text-blue-600 p-4 rounded-2xl"><FileSpreadsheet/> <span className="text-[10px] font-black uppercase">Xuất Excel</span></button>
             </div>
             <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
             <div className="space-y-4">
                <div className="space-y-1"><label className="text-[11px] font-black uppercase">Đơn giá nước:</label><input className="w-full bg-slate-100 p-4 rounded-xl text-xl font-black outline-none" type="number" step="0.1" value={config.waterRate} onChange={e => setConfig({...config, waterRate: parseSafe(e.target.value)})} /></div>
                <div className="space-y-1"><label className="text-[11px] font-black uppercase">Số tài khoản:</label><input className="w-full bg-white p-4 border rounded-xl font-black outline-none" type="text" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
                <div className="space-y-1"><label className="text-[11px] font-black uppercase">Tên chủ TK:</label><input className="w-full bg-white p-4 border rounded-xl font-black outline-none uppercase" type="text" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value})} /></div>
             </div>
             <button onClick={() => setView('list')} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black uppercase mt-10">Lưu & Về</button>
             <div className="text-center mt-10"><button onClick={() => { if(confirm("Xóa toàn bộ dữ liệu máy?")) { localStorage.clear(); location.reload(); } }} className="text-rose-500 font-black text-[10px] uppercase">Xóa dữ liệu máy</button></div>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white p-6 flex flex-col">
          <header className="flex items-center gap-4 mb-8"><button onClick={() => setView('list')}><ChevronLeft size={28}/></button><h1 className="text-xl font-black uppercase italic">Báo cáo</h1></header>
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-blue-50 p-6 rounded-3xl text-center"><p className="text-[10px] font-black uppercase text-blue-400">Khách hàng</p><p className="text-3xl font-black text-blue-600">{stats.totalCust}</p></div>
            <div className="bg-emerald-50 p-6 rounded-3xl text-center"><p className="text-[10px] font-black uppercase text-emerald-400">Đã ghi</p><p className="text-3xl font-black text-emerald-600">{stats.recorded}</p></div>
          </div>
          <div className="bg-white border-2 rounded-[2.5rem] p-6 space-y-4 shadow-sm flex-1">
             <div className="flex justify-between font-bold text-slate-500"><span>Tiêu thụ:</span><span className="text-slate-900">{stats.totalVol} m³</span></div>
             <div className="flex justify-between font-bold text-blue-600"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount)}</span></div>
             <div className="flex justify-between font-bold text-rose-600"><span>Nợ kỳ trước:</span><span>{formatCurrency(stats.totalOldDebt)}</span></div>
          </div>
          <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `BaoCao_${activeTab}`)} className="w-full bg-blue-600 text-white py-4.5 rounded-2xl font-black uppercase mt-8 flex justify-center items-center gap-2"><Download size={20}/> Xuất Excel</button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  CloudDownload, Settings, ChevronLeft, Search, Loader2, 
  X, Banknote, Save, Trash2, Pencil, Plus, Download, BarChart3, QrCode, Phone, Copy, Mic, FileJson, UploadCloud,
  MessageCircle, FileSpreadsheet, ExternalLink, ChevronRight, Sparkles, Landmark, CheckCheck
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { exportToExcel, parseExcelFile, normalizePhoneForZalo, formatCurrency } from './utils';
import { Customer } from './types';

const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

const App: React.FC = () => {
  // --- STATE ---
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('water_data_final_v16');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState(() => {
    const saved = localStorage.getItem('water_config_v16');
    return saved ? JSON.parse(saved) : { 
      waterRate: 16.5, sheetUrl1: '', sheetUrl2: '', 
      bankId: 'vba', accountNo: '8888942444224', accountName: 'TO TUAN KIET' 
    };
  });

  const [view, setView] = useState('list'); 
  const [activeTab, setActiveTab] = useState<'list1' | 'list2'>('list1');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showQr, setShowQr] = useState(false);
  const [onlyNonZalo, setOnlyNonZalo] = useState(false); 
  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);
  const [quickIndex, setQuickIndex] = useState('');
  const [paidInput, setPaidInput] = useState('');

  const [editForm, setEditForm] = useState({ name: '', address: '', phone: '', stt: 0, oldIndex: 0, oldDebt: 0, isZalo: false });
  const [showAddModal, setShowAddModal] = useState(false);
  const [addForm, setAddForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollTargetId = useRef<string | null>(null);

  // --- EFFECTS ---
  useEffect(() => {
    localStorage.setItem('water_data_final_v16', JSON.stringify(customers));
    localStorage.setItem('water_config_v16', JSON.stringify(config));
  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-blue-50');
          setTimeout(() => el.classList.remove('bg-blue-50'), 1500);
        }
        scrollTargetId.current = null;
      }, 100);
    }
  }, [view]);

  // --- MEMOS ---
  const filtered = useMemo(() => 
    customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      const s = searchQuery.toLowerCase();
      const matchSearch = String(c.name).toLowerCase().includes(s) || String(c.address).toLowerCase().includes(s) || String(c.phone).includes(s) || String(c.stt) === s;
      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return isCorrectTab && matchSearch && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt)
  , [customers, activeTab, searchQuery, onlyNonZalo]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const selectedCustomer = customers.find(c => c.id === selectedId);

  const currentUsage = useMemo(() => {
    if (!selectedCustomer) return { vol: 0, amount: 0, total: 0 };
    const ni = parseSafe(quickIndex);
    const vol = (ni > 0 && ni >= selectedCustomer.oldIndex) ? (ni - selectedCustomer.oldIndex) : 0;
    const amount = vol * config.waterRate;
    return { vol, amount, total: amount + selectedCustomer.oldDebt };
  }, [quickIndex, selectedCustomer, config.waterRate]);

  const qrTransferInfo = useMemo(() => {
    if (!selectedCustomer) return { amount: 0, content: '' };
    const cleanName = selectedCustomer.name.normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D")
      .replace(/[^a-zA-Z0-9 ]/g, "").toUpperCase();
    return {
      amount: Math.round(currentUsage.total * 1000),
      content: `TT NUOC STT${selectedCustomer.stt} ${cleanName}`
    };
  }, [selectedCustomer, currentUsage.total]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    return `https://img.vietqr.io/image/${config.bankId}-${config.accountNo}-compact.png?amount=${qrTransferInfo.amount}&addInfo=${encodeURIComponent(qrTransferInfo.content)}&accountName=${encodeURIComponent(config.accountName)}`;
  }, [selectedCustomer, qrTransferInfo, config]);

  // --- HANDLERS ---
  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Vui lòng nhập Link Script!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt} Trống)`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo
        }, config.waterRate));
        return [...other, ...mapped];
      });
      alert("Đồng bộ thành công!");
    } catch (e: any) { alert(`Lỗi: ${e.message}`); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const newData = [...prev];
        imported.forEach(item => {
          const idx = newData.findIndex(c => c.stt === item.stt && c.listType === item.listType);
          if (idx !== -1) newData[idx] = { ...newData[idx], ...item };
          else newData.push(item);
        });
        return newData;
      });
      alert("Đã gộp Excel thành công!");
    } catch (err: any) { alert("Lỗi Excel: " + err.message); } finally { setIsSyncing(false); }
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const currentIndex = filtered.findIndex(c => c.id === selectedId);
    let targetIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
    if (targetIndex >= 0 && targetIndex < filtered.length) {
      const nextCust = filtered[targetIndex];
      setSelectedId(nextCust.id);
      setQuickIndex(nextCust.newIndex > 0 ? nextCust.newIndex.toString() : "");
      setPaidInput(nextCust.paid > 0 ? nextCust.paid.toString() : "");
    }
  };

  const saveAndBack = (isThuDu: boolean = false) => {
    if (!selectedId) return;
    const finalPaid = isThuDu ? currentUsage.total.toString() : paidInput;
    const ni = parseSafe(quickIndex);
    const pi = parseSafe(finalPaid);
    setCustomers(prev => prev.map(c => 
      c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c
    ));
    scrollTargetId.current = selectedId;
    setView('list');
  };

  const startVoice = () => {
    const Speech = (window as any).webkitSpeechRecognition;
    if (!Speech) { alert("Trình duyệt không hỗ trợ giọng nói"); return; }
    const sr = new Speech();
    sr.lang = 'vi-VN';
    sr.onstart = () => setIsListening(true);
    sr.onresult = async (e: any) => {
      const text = e.results[0][0].transcript;
      setIsProcessingAI(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Ghi nước: "${text}"`,
          config: { systemInstruction: "Trích JSON: {name, newIndex}", responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || "{}");
        if (result.name && result.newIndex) {
          const found = customers.find(c => c.listType === activeTab && c.name.toLowerCase().includes(result.name.toLowerCase()));
          if (found) {
            setCustomers(prev => prev.map(c => c.id === found.id ? calculateRow({ ...c, newIndex: result.newIndex }, config.waterRate) : c));
            scrollTargetId.current = found.id;
          }
        }
      } catch (err) {} finally { setIsProcessingAI(false); }
    };
    sr.onend = () => setIsListening(false);
    sr.start();
  };

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">
      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase">{activeTab === 'list1' ? 'Bộ 01' : 'Bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setShowAddModal(true)} className="p-2 text-blue-600 active:scale-90"><Plus size={24}/></button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600 active:scale-90">
                {isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}
              </button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400 active:scale-90"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 flex gap-2">
            <div className="relative flex-1">
              <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
            </div>
            <button onClick={startVoice} className={`p-3 rounded-xl border transition-all ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-red-500 shadow-sm'}`}>
              <Mic size={20}/>
            </button>
            <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl text-blue-600 shadow-sm active:bg-blue-50"><BarChart3 size={20}/></button>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28 scroll-smooth">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? c.paid.toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all scroll-mt-24">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border transition-all ${c.isZalo ? 'bg-blue-600 text-white border-blue-600' : 'text-slate-300 border-slate-100'}`}><MessageCircle size={14}/></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="font-black uppercase text-[15px] truncate text-slate-900">{c.name}</h3>
                    <p className="text-[11px] text-slate-500 truncate mb-1.5">{c.address || '---'}</p>
                    <div className="flex items-center gap-2">
                      <button onClick={(e) => {e.stopPropagation(); const p = normalizePhoneForZalo(c.phone); setCustomers(prev => prev.map(it => it.id === c.id ? {...it, isZalo: true} : it)); window.location.assign(`https://zalo.me/${p}`);}} className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg border border-blue-100">ZALO</button>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className={`font-black text-[17px] tracking-tighter ${c.status === 'paid' ? 'text-emerald-700' : 'text-rose-700'}`}>{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 && <div className="text-[9px] font-black text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded mt-1">Số: {c.newIndex}</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${activeTab === 'list1' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${activeTab === 'list2' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4 animate-in slide-in-from-right duration-200">
          <header className="flex justify-between items-center mb-6 shrink-0">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400 active:text-blue-600"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400 active:text-blue-600"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => { setEditForm({ name: selectedCustomer.name, address: selectedCustomer.address, phone: selectedCustomer.phone, stt: selectedCustomer.stt, oldIndex: selectedCustomer.oldIndex, oldDebt: selectedCustomer.oldDebt, isZalo: !!selectedCustomer.isZalo }); setView('edit_customer'); }} className="p-3 bg-slate-50 rounded-full border shadow-sm"><Pencil size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>
          <div className="flex-1 space-y-6 overflow-y-auto px-2">
            <div className="border-l-4 border-blue-600 pl-4">
              <h2 className="font-black uppercase text-xl text-slate-900">{selectedCustomer.name}</h2>
              <p className="text-sm text-slate-500 italic">{selectedCustomer.address}</p>
            </div>
            <div className="bg-slate-50 rounded-3xl p-6 border shadow-inner text-center">
              <div className="grid grid-cols-2 gap-4">
                <div><p className="text-[10px] font-black uppercase text-slate-400">Số cũ</p><div className="text-4xl font-black">{selectedCustomer.oldIndex}</div></div>
                <div><p className="text-[10px] font-black uppercase text-blue-600">Số mới</p><input autoFocus type="number" className="w-full text-center text-4xl font-black text-blue-600 bg-transparent outline-none" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} /></div>
              </div>
            </div>
            <div className="space-y-3 bg-white border p-5 rounded-3xl shadow-sm border-slate-100 text-lg">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(currentUsage.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ cũ:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t border-dashed my-2"></div>
              <div className="flex justify-between items-center font-black text-blue-600"><span>Tổng cộng:</span><span className="text-3xl tracking-tighter">{formatCurrency(currentUsage.total)}</span></div>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 pt-4 border-t shrink-0">
            <button onClick={() => saveAndBack(true)} className="bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-lg">Thu đủ</button>
            <button onClick={() => saveAndBack(false)} className="bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Lưu & Về</button>
          </div>
          {showQr && (
            <div className="fixed inset-0 bg-white/98 z-[60] flex flex-col items-center justify-center p-6 animate-in fade-in duration-200">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border-2 w-full max-w-sm text-center">
                <p className="font-black text-blue-600 uppercase mb-2 italic">Thanh toán Agribank</p>
                <div className="mb-4 bg-blue-50/50 p-4 rounded-2xl border border-blue-100 text-left text-[11px] space-y-1.5 font-bold">
                   <div className="flex justify-between text-slate-500"><span>Số tiền:</span><span className="text-blue-700 font-black">{new Intl.NumberFormat('vi-VN').format(qrTransferInfo.amount)} VNĐ</span></div>
                   <div className="flex justify-between text-slate-500"><span>Nội dung:</span><span className="text-slate-900 font-black uppercase">{qrTransferInfo.content}</span></div>
                </div>
                <img src={qrUrl} className="w-full aspect-square object-contain mb-4" alt="QR" />
                <button onClick={() => setShowQr(false)} className="w-full bg-[#111827] text-white py-4 rounded-2xl font-black uppercase tracking-widest active:scale-95">Đóng mã QR</button>
              </div>
            </div>
          )}
        </div>
      )}

      {view === 'edit_customer' && (
        <div className="h-full bg-white p-6 animate-in slide-in-from-bottom duration-200 overflow-y-auto">
          <header className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Sửa thông tin</h2><button onClick={() => setView('detail')}><X/></button></header>
          <div className="space-y-4 pb-10">
            <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} />
            <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={editForm.address} onChange={e => setEditForm({...editForm, address: e.target.value})} />
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1"><label className="text-[10px] font-black">STT</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.stt} onChange={e => setEditForm({...editForm, stt: parseInt(e.target.value)})} /></div>
              <div className="space-y-1"><label className="text-[10px] font-black">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldIndex} onChange={e => setEditForm({...editForm, oldIndex: parseFloat(e.target.value)})} /></div>
            </div>
            <div className="space-y-1"><label className="text-[10px] font-black">Nợ cũ (K)</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldDebt} onChange={e => setEditForm({...editForm, oldDebt: parseFloat(e.target.value)})} /></div>
            <button onClick={() => { if(!selectedId) return; setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({...c, ...editForm}, config.waterRate) : c)); setView('detail'); }} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-4">Lưu thay đổi</button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic">Thêm khách hàng</h2><button onClick={() => setShowAddModal(false)}><X/></button></div>
            <div className="space-y-4">
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="STT" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value)})} />
                <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Số cũ" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value)})} />
              </div>
              <button onClick={() => { const nc = calculateRow({id: `custom-${Date.now()}`, ...addForm, listType: activeTab, newIndex: 0, paid: 0}, config.waterRate); setCustomers(prev => [...prev, nc]); setShowAddModal(false); setAddForm({name:'', address:'', phone:'', stt:stats.totalCust+2, oldIndex:0, oldDebt:0, isZalo:false}); }} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Tạo mới</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full active:scale-90"><X size={20}/></button></header>
