                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400 active:text-blue-600"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => { setEditForm({ name: selectedCustomer.name, address: selectedCustomer.address, phone: selectedCustomer.phone, stt: selectedCustomer.stt, oldIndex: selectedCustomer.oldIndex, oldDebt: selectedCustomer.oldDebt, isZalo: !!selectedCustomer.isZalo }); setView('edit_customer'); }} className="p-3 bg-slate-50 rounded-full border border-slate-200 shadow-sm"><Pencil size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl active:scale-90 transition-all"><QrCode size={22}/></button>
            </div>
          </header>
