            <div className="space-y-3 bg-white border border-slate-100 p-5 rounded-3xl shadow-sm text-lg">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(currentUsage.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ kỳ trước:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t border-dashed border-slate-200 my-2"></div>
              <div className="flex justify-between items-center font-black text-blue-600"><span>Tổng cộng:</span><span className="text-3xl tracking-tighter">{formatCurrency(currentUsage.total)}</span></div>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-100 shrink-0">
            <button onClick={() => saveAndBack(true)} className="bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase shadow-lg active:scale-95 transition-all">Thu đủ</button>
            <button onClick={() => saveAndBack(false)} className="bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl active:scale-95 transition-all">Lưu & Về</button>
          </div>
          {showQr && (
            <div className="fixed inset-0 bg-white/98 z-[60] flex flex-col items-center justify-center p-6 animate-in fade-in duration-200">
              <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border-2 border-slate-100 w-full max-w-sm text-center">
                <p className="font-black text-blue-600 uppercase mb-2 italic tracking-tight">Thanh toán VietQR</p>
                <div className="mb-4 bg-blue-50/50 p-4 rounded-2xl border border-blue-100 text-left text-[11px] space-y-1.5 font-bold">
                   <div className="flex justify-between text-slate-500"><span>Số tiền:</span><span className="text-blue-700 font-black">{new Intl.NumberFormat('vi-VN').format(Math.round(currentUsage.total * 1000))} VNĐ</span></div>
                   <div className="flex justify-between text-slate-500"><span>Nội dung:</span><span className="text-slate-900 font-black uppercase">TT NUOC STT{selectedCustomer.stt}</span></div>
                </div>
                <img src={qrUrl} className="w-full aspect-square object-contain mb-4" alt="Mã VietQR" />
                <button onClick={() => setShowQr(false)} className="w-full bg-[#111827] text-white py-4 rounded-2xl font-black uppercase tracking-widest active:scale-95 transition-all shadow-lg">Đóng mã QR</button>
              </div>
            </div>
          )}
        </div>
      )}

      {view === 'edit_customer' && (
        <div className="h-full bg-white p-6 animate-in slide-in-from-bottom duration-200 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Sửa thông tin</h2><button onClick={() => setView('detail')} className="p-2 bg-slate-100 rounded-full"><X/></button></header>
          <div className="space-y-4 pb-10">
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Họ và Tên:</label><input className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none focus:border-blue-500" value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Địa chỉ:</label><input className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none focus:border-blue-500" value={editForm.address} onChange={e => setEditForm({...editForm, address: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Số điện thoại:</label><input className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none focus:border-blue-500" value={editForm.phone} onChange={e => setEditForm({...editForm, phone: e.target.value})} /></div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">STT:</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" value={editForm.stt} onChange={e => setEditForm({...editForm, stt: parseInt(e.target.value)})} /></div>
              <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Số cũ:</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" value={editForm.oldIndex} onChange={e => setEditForm({...editForm, oldIndex: parseFloat(e.target.value)})} /></div>
            </div>
            <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Nợ cũ (K):</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" value={editForm.oldDebt} onChange={e => setEditForm({...editForm, oldDebt: parseFloat(e.target.value)})} /></div>
            <button onClick={() => { if(!selectedId) return; setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({...c, ...editForm}, config.waterRate) : c)); setView('detail'); }} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-4 active:scale-95 transition-all">Lưu thay đổi</button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic text-slate-800">Thêm khách hàng</h2><button onClick={() => setShowAddModal(false)}><X/></button></div>
            <div className="space-y-4">
              <input className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" placeholder="STT" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value)})} />
                <input type="number" className="w-full bg-slate-50 p-4 rounded-xl border border-slate-200 font-bold outline-none" placeholder="Số cũ" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value)})} />
              </div>
              <button onClick={() => { const nc = calculateRow({id: `custom-${Date.now()}`, ...addForm, listType: activeTab, newIndex: 0, paid: 0}, config.waterRate); setCustomers(prev => [...prev, nc]); setShowAddModal(false); setAddForm({name:'', address:'', phone:'', stt:stats.totalCust+2, oldIndex:0, oldDebt:0, isZalo:false}); }} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-2 active:scale-95 transition-all">Tạo mới</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full active:scale-90"><X size={20}/></button></header>
          <div className="space-y-5 pb-20">
             <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 bg-blue-600 text-white p-4 rounded-2xl shadow-lg active:scale-95 transition-all"><UploadCloud size={24}/> <span className="text-[10px] font-black uppercase">Gộp Excel</span></button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `SaoLuu_${activeTab}`)} className="flex flex-col items-center gap-2 border-2 border-blue-600 text-blue-600 p-4 rounded-2xl shadow-sm active:scale-95 transition-all"><FileSpreadsheet size={24}/> <span className="text-[10px] font-black uppercase">Xuất Excel</span></button>
             </div>
             <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
             <div className="space-y-4 pt-4">
                <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Đơn giá nước (K/m³):</label><input className="w-full bg-slate-100 p-4 rounded-xl text-xl font-black text-blue-600 outline-none border border-slate-100 shadow-inner" type="number" step="0.1" value={config.waterRate} onChange={e => setConfig({...config, waterRate: parseSafe(e.target.value)})} /></div>
                <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Mã Ngân hàng (Ví dụ: vba, mb):</label><input className="w-full bg-white p-4 border rounded-xl font-black outline-none border-slate-200 focus:border-blue-500" type="text" value={config.bankId} onChange={e => setConfig({...config, bankId: e.target.value})} /></div>
                <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Số tài khoản:</label><input className="w-full bg-white p-4 border rounded-xl font-black outline-none border-slate-200 focus:border-blue-500" type="text" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
                <div className="space-y-1"><label className="text-[11px] font-black uppercase text-slate-500 ml-1 italic">Tên chủ TK:</label><input className="w-full bg-white p-4 border rounded-xl font-black uppercase outline-none border-slate-200 focus:border-blue-500" type="text" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value})} /></div>
                <div className="h-px bg-slate-100 my-4"></div>
                <div className="space-y-1"><label className="text-[11px] font-black uppercase text-blue-600 ml-1 italic">Link Script (Dành cho bộ dữ liệu):</label><input className="w-full bg-white p-3 border rounded-xl text-[10px] outline-none border-slate-200 focus:border-blue-500" type="text" value={config.sheetUrl1} onChange={e => setConfig({...config, sheetUrl1: e.target.value})} /></div>
             </div>
             <button onClick={() => setView('list')} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95 transition-all mt-4">Lưu & Về</button>
             <div className="pt-8 text-center"><button onClick={() => { if(confirm("Xóa toàn bộ dữ liệu máy?")) { localStorage.clear(); location.reload(); } }} className="text-rose-500 font-black text-[10px] uppercase tracking-widest active:opacity-50"><Trash2 size={12} className="inline mr-1"/> Xóa dữ liệu máy</button></div>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white flex flex-col p-6 animate-in slide-in-from-bottom duration-200">
          <header className="flex items-center gap-4 mb-8 shrink-0"><button onClick={() => setView('list')} className="p-2 bg-slate-50 rounded-full active:scale-90"><ChevronLeft size={28}/></button><h1 className="text-xl font-black uppercase italic text-slate-800">Báo cáo</h1></header>
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-blue-50 p-6 rounded-3xl text-center shadow-sm border border-blue-100"><p className="text-[10px] font-black uppercase text-blue-400 mb-1">Khách hàng</p><p className="text-3xl font-black text-blue-600">{stats.totalCust}</p></div>
