          </div>
          <div className="bg-white border-2 rounded-[2.5rem] p-6 space-y-4 shadow-sm border-slate-100 flex-1 overflow-y-auto">
             <div className="flex justify-between font-bold text-slate-500 italic"><span>Tiêu thụ:</span><span className="text-slate-900">{stats.totalVol} m³</span></div>
             <div className="flex justify-between font-bold text-blue-600 uppercase text-sm italic"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount)}</span></div>
             <div className="flex justify-between font-bold text-rose-600 uppercase text-sm italic"><span>Nợ kỳ trước:</span><span>{formatCurrency(stats.totalOldDebt)}</span></div>
             <div className="h-px bg-slate-50 my-2"></div>
             <div className="flex justify-between font-black text-slate-900 uppercase"><span>Tổng cần thu:</span><span>{formatCurrency(stats.totalAmount + stats.totalOldDebt)}</span></div>
          </div>
          <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `BaoCao_${activeTab}`)} className="w-full bg-blue-600 text-white py-4.5 rounded-2xl font-black uppercase shadow-xl mt-8 flex justify-center items-center gap-2 active:scale-95 transition-all"><Download size={20}/> Xuất Excel</button>
        </div>
      )}
    </div>
  );
};

export default App;
